const a = [
  {"id":3,"text":"Where is the neuropil of the spinal cord most abundant?","explanation":null,"reference":"Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 107.","responses":[{"text":"Perikarya","correct":false,"visible":false},{"text":"Synapsis","correct":false,"visible":false},{"text":"Gray matter","correct":true,"visible":false},{"text":"Neuroglia","correct":false,"visible":false},{"text":"Unmyelinated axons","correct":false,"visible":false}]},{"id":12,"text":"A 30-year-old man reported to the emergency department with a complaint of a dog bite on the right arm. The casualty is conscious but the wound is bleeding. No previous medical or surgical history is reported. After history taking, what is the first step of management?","explanation":null,"reference":"Ellis R, Ellis C. Dog and cat bites. AFP. 2014;90(4):239-243. Accessed March 29, 2022. https://www.aafp.org/afp/2014/0815/p239.html","responses":[{"text":"Administration of anti-rabies immunoglobulin","correct":false,"visible":false},{"text":"Washing and debridement of the wound","correct":true,"visible":false},{"text":"Administration of anti-rabies vaccine","correct":false,"visible":false},{"text":"Administration of IV saline","correct":false,"visible":false},{"text":"Testing the dog for rabies","correct":false,"visible":false}]},{"id":16,"text":"What does the white matter of the spinal cord consist of?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 2.","responses":[{"text":"Perikarya","correct":false,"visible":false},{"text":"Myelinated axon","correct":true,"visible":false},{"text":"Dendrites","correct":false,"visible":false},{"text":"Neuroglia","correct":false,"visible":false},{"text":"Blood vessels","correct":false,"visible":false}]},{"id":18,"text":"The neostriatum consists of which of the following pairs of structures?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 317.","responses":[{"text":"Putamen and lentiform nucleus","correct":false,"visible":false},{"text":"Lentiform and globus pallidus","correct":false,"visible":false},{"text":"Putamen and globus pallidus","correct":false,"visible":false},{"text":"Lentiform and caudate nucleus","correct":false,"visible":false},{"text":"Putamen and caudate nucleus","correct":true,"visible":false}]},{"id":19,"text":"The suprachiasmatic nucleus is responsible for which of the following functions?","explanation":null,"reference":"Ma MA, Morrison EH. Neuroanatomy, nucleus suprachiasmatic. In: StatPearls. StatPearls Publishing; 2022. Accessed March 29, 2022. http://www.ncbi.nlm.nih.gov/books/NBK546664/","responses":[{"text":"Thermoregulation","correct":false,"visible":false},{"text":"Regulation of body's circadian rhythym","correct":true,"visible":false},{"text":"Release of oxytocin","correct":false,"visible":false},{"text":"Release of anti-diuretic hormone (ADH)","correct":false,"visible":false},{"text":"Control of feeding impulses","correct":false,"visible":false}]},{"id":25,"text":"Which one of the following statements refers to red neurons?","explanation":null,"reference":"Garman RH. Histology of the central nervous system. Toxicologic Pathology. Published January 2011. Accessed March 30, 2022. http://journals.sagepub.com/doi/10.1177/0192623310389621","responses":[{"text":"Abnormal vacuolization of neuron","correct":false,"visible":false},{"text":"Structural loss along with functional loss of the neuron","correct":false,"visible":false},{"text":"Reactive astrogliosis","correct":false,"visible":false},{"text":"Neurons having bright pink cytoplasm with large nucleus and numerous stout ramifying processes","correct":false,"visible":false},{"text":"Shrinkage of cell body, loss of nissl substance or pyknosis of nucleus","correct":true,"visible":false}]},{"id":26,"text":"A 15-year-old boy presents with a fall and fracture of the temporal bone of the skull. On computed tomography (CT) scan, he is found to have an epidural hematoma. What is the most common cause of the hematoma?","explanation":null,"reference":"Khairat A, Waseem M. Epidural hematoma. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK518982/","responses":[{"text":"Ehlers-Danlos syndrome","correct":false,"visible":false},{"text":"Rupture of bridging veins","correct":false,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Rupture of middle meningeal artery","correct":true,"visible":false},{"text":"Autosomal polycystic kidney disease","correct":false,"visible":false}]},{"id":27,"text":"A 29-year-old man steps on a broken bottle with the base of his right foot. His right leg immediately flexes and his left leg extends. What is this reflex called?","explanation":null,"reference":"Purves D, Augustine GJ, Fitzpatrick D, et al. Flexion reflex pathways. Neuroscience 2nd edition. Published online 2001. Accessed March 30, 2022. https://www.ncbi.nlm.nih.gov/books/NBK11091/","responses":[{"text":"Walking reflex","correct":false,"visible":false},{"text":"Stretch reflex","correct":false,"visible":false},{"text":"Patellar reflex","correct":false,"visible":false},{"text":"Golgi tendon reflex","correct":false,"visible":false},{"text":"Crossed extensor reflex","correct":true,"visible":false}]},{"id":29,"text":"A 50-year-old patient with a history of hypertension is brought to the outpatient department. Examination reveals weakness and loss of sensation mainly affecting right leg, right foot, and perineum. Which one of the following arteries is occluded?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 483.","responses":[{"text":"Left middle cerebral artery","correct":false,"visible":false},{"text":"Right middle cerebral artery","correct":false,"visible":false},{"text":"Right anterior cerebral artery","correct":false,"visible":false},{"text":"Posterior cerebral artery","correct":false,"visible":false},{"text":"Left anterior cerebral artery","correct":true,"visible":false}]},{"id":35,"text":"Which of the following is the corpus striatum a part of?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 261.","responses":[{"text":"Subthalamus","correct":false,"visible":false},{"text":"Limbic system","correct":false,"visible":false},{"text":"Thalamus","correct":false,"visible":false},{"text":"Basal ganglia","correct":true,"visible":false},{"text":"Reticular formation","correct":false,"visible":false}]},{"id":41,"text":"A 79-year-old woman was driving when she had a sudden severe headache. She drove to a service station, stopped the car and slumped over the wheel. She was taken to emergency, where she remained comatose and died 6 hours later. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 182.","responses":[{"text":"Cerebral hematoma","correct":false,"visible":false},{"text":"Cerebral ischemia","correct":false,"visible":false},{"text":"Cerebral edema","correct":false,"visible":false},{"text":"Thromboembolism along with cerebral infarction","correct":false,"visible":false},{"text":"Rupture of berry aneurysm","correct":true,"visible":false}]},{"id":46,"text":"Which one of the following is the major part of the limbic system?","explanation":null,"reference":"Torrico TJ, Abdijadid S. Neuroanatomy, limbic system. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK538491/","responses":[{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Opioid receptor","correct":false,"visible":false},{"text":"Pineal body","correct":false,"visible":false},{"text":"Thalamus","correct":false,"visible":false},{"text":"Hypothalamus","correct":true,"visible":false}]},{"id":48,"text":"A child presented to the emergency department with a complaint of a dog bite in the right arm. He was conscious but bleeding from the wound site. The child has completed the EPI vaccination and no significant past medical or surgical history. After documenting the detail of the dog bite, what is the vaccination plan for this patient?","explanation":null,"reference":"Rabies postexposure prophylaxis (Pep) | medical care | rabies | cdc. Published June 11, 2019. Accessed March 30, 2022. https://www.cdc.gov/rabies/medical_care/index.html","responses":[{"text":"Anti-rabies vaccine and appropriate antibiotics","correct":false,"visible":false},{"text":"Anti-rabies vaccine and usage of immunoglobulin","correct":true,"visible":false},{"text":"Anti-rabies vaccine of both the dog and the child","correct":false,"visible":false},{"text":"Anti-rabies vaccine and cleaning the wound","correct":false,"visible":false},{"text":"Anti-rabies vaccine infiltration into the wound","correct":false,"visible":false}]},{"id":49,"text":"A newborn baby was brought to the neurology outpatient department because the large size of the fetal head-MRI shows fluid in the lateral ventricle. The appropriate part of the lateral ventricle formed by the head of the caudate nucleus is?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 311.","responses":[{"text":"Superior horn","correct":false,"visible":false},{"text":"Posterior horn","correct":false,"visible":false},{"text":"Anterior horn","correct":true,"visible":false},{"text":"Inferior horn","correct":false,"visible":false},{"text":"Medial horn","correct":false,"visible":false}]},{"id":50,"text":"Which of the following best defines memory?","explanation":null,"reference":"Zlotnik G, Vansintjan A. Memory: an extended definition. Frontiers in Psychology. Published November 7, 2019. Accessed March 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6853990/","responses":[{"text":"Skills of learning","correct":false,"visible":false},{"text":"Ability to store, retain, and recall information","correct":true,"visible":false},{"text":"Genetic control of brain","correct":false,"visible":false},{"text":"Ability to rest ourselves","correct":false,"visible":false},{"text":"Forgetting a movie","correct":false,"visible":false}]},{"id":52,"text":"Which structure is present superior to the pons and inferior to the thalamus?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 212.","responses":[{"text":"Midbrain","correct":true,"visible":false},{"text":"Medulla oblongata","correct":false,"visible":false},{"text":"Fourth ventricle","correct":false,"visible":false},{"text":"Cerebellum","correct":false,"visible":false},{"text":"Lateral ventricle","correct":false,"visible":false}]},{"id":53,"text":"The molecular layer of the cerebellar cortex does not contain which of the following?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 231-233.","responses":[{"text":"Neuroglia","correct":false,"visible":false},{"text":"Parallel fibers of granular cells axons","correct":false,"visible":false},{"text":"Stellate cells","correct":false,"visible":false},{"text":"Purkinje cells","correct":true,"visible":false},{"text":"Basket cells","correct":false,"visible":false}]},{"id":54,"text":"Which is the most safest site for collecting cerebrospinal fluid?","explanation":null,"reference":"Jane LA, Wray AA. Lumbar puncture. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK557553/","responses":[{"text":"Thoraco lumbar region","correct":false,"visible":false},{"text":"Thoracic vertebrae","correct":false,"visible":false},{"text":"Sacro iliac region","correct":false,"visible":false},{"text":"Illiac region","correct":false,"visible":false},{"text":"Lumbar region","correct":true,"visible":false}]},{"id":55,"text":"Which of the following is the most inappropriate statement about malformation and developmental diseases of CNS?","explanation":null,"reference":"(1) Kaleelullah RA, Garugula N. Teratogenic genesis in fetal malformations. Cureus. Accessed March 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7937350/ (2) Barkovich AJ, Millen KJ, Dobyns WB. A developmental and genetic classification for midbrain-hindbrain malformations. Brain: A Journal of Neurology.","responses":[{"text":"May occur due to deficiency of vitamin D","correct":true,"visible":false},{"text":"Many toxic compounds have teratogenic effects","correct":false,"visible":false},{"text":"Mutation of genes that control body patterning","correct":false,"visible":false},{"text":"Aberration of signaling molecules that control body patterning","correct":false,"visible":false},{"text":"Many infectious agents have teratogenic effects","correct":false,"visible":false}]},{"id":56,"text":"Myasthenia gravis is primarily a pathology of which structure?","explanation":null,"reference":"Beloor Suresh A, Asuncion RMD. Myasthenia gravis. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK559331/","responses":[{"text":"Motor neuron","correct":false,"visible":false},{"text":"Spinal cord","correct":false,"visible":false},{"text":"Cerebellum","correct":false,"visible":false},{"text":"Peripheral nerve","correct":false,"visible":false},{"text":"Neuromuscular junction","correct":true,"visible":false}]},{"id":57,"text":"The dura mater does not receive innervation from which of the following?","explanation":null,"reference":"Kekere V, Alsayouri K. Anatomy, head and neck, dura mater. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK545301/","responses":[{"text":"C3","correct":false,"visible":false},{"text":"C1","correct":false,"visible":false},{"text":"C2","correct":false,"visible":false},{"text":"Trigeminal","correct":false,"visible":false},{"text":"C4","correct":true,"visible":false}]},{"id":58,"text":"Use of which of the following prevents the occurrence of neural tube defects?","explanation":null,"reference":"Folic acid: the vitamin that helps prevent birth defects. Accessed March 30, 2022. https://www.health.ny.gov/publications/1335/","responses":[{"text":"Vitamin D","correct":false,"visible":false},{"text":"Vitamin C","correct":false,"visible":false},{"text":"Vitamin A","correct":false,"visible":false},{"text":"Vitamin K","correct":false,"visible":false},{"text":"Folic acid","correct":true,"visible":false}]},{"id":59,"text":"Which of the following is NOT shown by the neuroglial cells?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 53, 54, 55, 56.","responses":[{"text":"Capable to divide through life","correct":false,"visible":false},{"text":"Can be best studied with routine staining techniques","correct":true,"visible":false},{"text":"They are non-neuronal cells of CNS","correct":false,"visible":false},{"text":"Arise mostly from neuroectoderm","correct":false,"visible":false},{"text":"They are five to ten times more abundant than neurons","correct":false,"visible":false}]},{"id":60,"text":"Neurotransmitters (catecholamines) are mainly derived from which amino acid?","explanation":null,"reference":"Catecholamine synthesis - an overview | sciencedirect topics. Accessed March 28, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/catecholamine-synthesis","responses":[{"text":"Tryptophan","correct":false,"visible":false},{"text":"Alanine","correct":false,"visible":false},{"text":"Phenylalanine","correct":false,"visible":false},{"text":"Glycine","correct":false,"visible":false},{"text":"Tyrosine","correct":true,"visible":false}]},{"id":61,"text":"Degeneration of nigrostriatal dopaminergic neurons occurs in which of the following conditions?","explanation":null,"reference":"Zafar S, Yaddanapudi SS. Parkinson disease. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK470193/","responses":[{"text":"Epilepsy","correct":false,"visible":false},{"text":"Migraine","correct":false,"visible":false},{"text":"Huntington's chorea","correct":false,"visible":false},{"text":"Alzheimer's disease","correct":false,"visible":false},{"text":"Paralysis agitans","correct":true,"visible":false}]},{"id":62,"text":"A 36-year-old man fell from a height of 10 feet. As a consequence, he now suffers from incontinence and weakness in the lower limbs. Which of the following statements is correct?","explanation":null,"reference":"Cauda equina syndrome – symptoms, causes, diagnosis and treatments. Accessed March 27, 2022. https://www.aans.org/","responses":[{"text":"Imaging of dorsal spine should be done","correct":false,"visible":false},{"text":"Imaging of lumbosacral region should be done","correct":true,"visible":false},{"text":"Involvement of cervical spine C4 level","correct":false,"visible":false},{"text":"The middle cerebral artery is involved","correct":false,"visible":false},{"text":"The posterior cerebral artery is involved","correct":false,"visible":false}]},{"id":63,"text":"A 25-year-old female had a head injury. She is diagnosed with a case of Kluver Bucy syndrome. Which one of the following signs is not present?","explanation":null,"reference":"M Das J, Siddiqui W. Kluver bucy syndrome. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK544221/","responses":[{"text":"Paralysis of one side of body","correct":true,"visible":false},{"text":"Increased sexuality","correct":false,"visible":false},{"text":"Compulsive tendency to place things in mouth","correct":false,"visible":false},{"text":"Changes in eating behavior","correct":false,"visible":false},{"text":"Decrease emotionality","correct":false,"visible":false}]},{"id":64,"text":"Obstruction of the flow of cerebrospinal fluid leads to which of the following conditions?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 466.","responses":[{"text":"Meningitis","correct":false,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Parkinsonism","correct":false,"visible":false},{"text":"Tumor formation","correct":false,"visible":false},{"text":"Hydrocephalus","correct":true,"visible":false}]},{"id":66,"text":"Which of the following regarding oligodendroglia is true?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 58.","responses":[{"text":"Can myelinate more than one axon per cell","correct":true,"visible":false},{"text":"Helps in forming pia meningeal layer","correct":false,"visible":false},{"text":"Supporting cells of PNS","correct":false,"visible":false},{"text":"Helps in blood brain barrier formation/maintenance","correct":false,"visible":false},{"text":"Phagocytic cells","correct":false,"visible":false}]},{"id":70,"text":"At what rate does peripheral nerve fiber regenerate?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 110.","responses":[{"text":"3 mm/day","correct":true,"visible":false},{"text":"200 mm/day","correct":false,"visible":false},{"text":"0.1 mm/day","correct":false,"visible":false},{"text":"400 mm/day","correct":false,"visible":false},{"text":"100 mm/day","correct":false,"visible":false}]},{"id":72,"text":"What hormone is synthesized by the pineal gland?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 256.","responses":[{"text":"Melatonin","correct":true,"visible":false},{"text":"Acetylcholine","correct":false,"visible":false},{"text":"Glutamate","correct":false,"visible":false},{"text":"Adrenaline","correct":false,"visible":false},{"text":"Endorphin","correct":false,"visible":false}]},{"id":75,"text":"The caudate nucleus, putamen, and the globus pallidus collectively make up which structure?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 310.","responses":[{"text":"Cerebellum","correct":false,"visible":false},{"text":"Limbic system","correct":false,"visible":false},{"text":"Basal nuclei","correct":true,"visible":false},{"text":"Reticular formation","correct":false,"visible":false},{"text":"Amygdala","correct":false,"visible":false}]},{"id":80,"text":"Which of the following features is not present in the Purkinje cells?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 231.","responses":[{"text":"Arranged as single row between molecular and granular layer","correct":false,"visible":false},{"text":"Having branching dendrites that ascent at molecular layer","correct":false,"visible":false},{"text":"Largest output neuron of cerebellar cortex","correct":false,"visible":false},{"text":"Can be best studied by routine staining techniques","correct":true,"visible":false},{"text":"Collateral axon that enters the white mater","correct":false,"visible":false}]},{"id":81,"text":"Which of the following is an indolamine derived from tryptophan?","explanation":null,"reference":"Indolamines - an overview | sciencedirect topics. Accessed March 29, 2022. https://www.sciencedirect.com/topics/neuroscience/indolamines","responses":[{"text":"Serotonin","correct":true,"visible":false},{"text":"Chitin","correct":false,"visible":false},{"text":"Prostaglandin","correct":false,"visible":false},{"text":"Leukotriene","correct":false,"visible":false},{"text":"Dopamine","correct":false,"visible":false}]},{"id":84,"text":"Which statement is inappropriate regarding the dorsal horn of the grey matter of the spinal cord?","explanation":null,"reference":"(1) Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 139. \r\n\r\n(2) \r\nPurves D, Augustine GJ, Fitzpatrick D, et al. The internal anatomy of the spinal cord. Neuroscience 2nd edition. Published online 2001. Accessed March 30, 2022. https://www.ncbi.nlm.nih.gov/books/NBK11008/","responses":[{"text":"It receives and processes sensory inputs","correct":false,"visible":false},{"text":"It is found in all levels of spinal cord","correct":false,"visible":false},{"text":"It is less bulky in size than ventral horn of grey matter","correct":false,"visible":false},{"text":"It includes substantia gelatinosa which is homologous to spinal trigeminal nucleus","correct":false,"visible":false},{"text":"It is found in cervical region only","correct":true,"visible":false}]},{"id":87,"text":"Which of the following is wrong regarding the hypothalamus?","explanation":null,"reference":"Bear MH, Reddy V, Bollu PC. Neuroanatomy, hypothalamus. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK525993/","responses":[{"text":"Weights around 4gms","correct":false,"visible":false},{"text":"Preoptic area lies infront of hypothalamus","correct":false,"visible":false},{"text":"Hypothalamic sulcus separates hypothalamus from thalamus","correct":false,"visible":false},{"text":"Extends from optic chiasm to mamillary bodies","correct":false,"visible":false},{"text":"Inferior to hypothalamus lies third ventricle","correct":true,"visible":false}]},{"id":95,"text":"Which of the following histological characteristics is not part of the cerebral cortex?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 287.","responses":[{"text":"Contains six layers in all areas of cortex","correct":true,"visible":false},{"text":"Neocortex shows alternate dark and light bands on histological appearance","correct":false,"visible":false},{"text":"Paleocortex is heterogenous","correct":false,"visible":false},{"text":"Isocortex is homogenetically typical","correct":false,"visible":false},{"text":"Archicortex has hetrogenous, three layers","correct":false,"visible":false}]},{"id":96,"text":"REM sleep is characterized by which of the following?","explanation":null,"reference":"Hall JE. Guyton and Hall Textbook of Medical Physiology. 13th ed. Elsevier; 2016: 763.","responses":[{"text":"Alpha waves of EEG","correct":false,"visible":false},{"text":"High voltage, low frequency EEG activity","correct":false,"visible":false},{"text":"70% - 80% of the total sleeping period","correct":false,"visible":false},{"text":"Absence of dreams","correct":false,"visible":false},{"text":"Rapid conjugate movements of the eye balls","correct":true,"visible":false}]},{"id":98,"text":"Reticular formation nuclei concerned with autonomic regulation of respiration pressure are present in?","explanation":null,"reference":"Mangold SA, M Das J. Neuroanatomy, reticular formation. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK556102/","responses":[{"text":"Lateral group","correct":true,"visible":false},{"text":"Paramedian group","correct":false,"visible":false},{"text":"Medial group","correct":false,"visible":false},{"text":"Raphe group","correct":false,"visible":false},{"text":"Intermediate group","correct":false,"visible":false}]},{"id":101,"text":"Which nucleus of the hypothalamus contains the satiety center?","explanation":null,"reference":"Vettor R, Fabris R, Pagano C, Federspil G. Neuroendocrine regulation of eating behavior. Journal of Endocrinological Investigation.","responses":[{"text":"Paraventricular nucleus","correct":false,"visible":false},{"text":"Ventromedial nucleus","correct":true,"visible":false},{"text":"Supraoptic nucleus","correct":false,"visible":false},{"text":"Posterolateral nucleus","correct":false,"visible":false},{"text":"Suprachiasmatic nucleus","correct":false,"visible":false}]},{"id":102,"text":"A 54-year-old man got a head injury during a road traffic accident. He was treated by a neurosurgeon in a tertiary care hospital. On examination, his reflexes are slow, there is a loss of power in the muscles and when he starts movement he feels difficulty turning off his movements. The presenting symptoms present when which one of the following parts of CNS is damaged?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 243, 244.","responses":[{"text":"Midbrain","correct":false,"visible":false},{"text":"Reticular formation","correct":false,"visible":false},{"text":"Primary motor area of cerebral cortex","correct":false,"visible":false},{"text":"Cerebellum","correct":true,"visible":false},{"text":"Pyramid of Medulla oblongata","correct":false,"visible":false}]},{"id":113,"text":"Under the morphological classification of the neurons, the bipolar neurons are the ones that bear a single axon and a single dendrite that emerges from the opposite poles of the spindle-shaped body. Which one of the following is an example of a bipolar neuron?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 38.","responses":[{"text":"Purkinje cells of the cerebral cortex","correct":false,"visible":false},{"text":"Dorsal root ganglion of the spinal nerves","correct":false,"visible":false},{"text":"Neurons in the cochlear and vestibular ganglia","correct":true,"visible":false},{"text":"Sensory ganglia of cranial nerves","correct":false,"visible":false},{"text":"Mesencephalic nucleus of trigeminal nerve","correct":false,"visible":false}]},{"id":115,"text":"Serotonergic innervations of suprachiasmatic nuclei of the hypothalamus involve which of the following?","explanation":null,"reference":"Ma MA, Morrison EH. Neuroanatomy, nucleus suprachiasmatic. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK546664/","responses":[{"text":"Hallucinations","correct":false,"visible":false},{"text":"Deep sleep","correct":false,"visible":false},{"text":"Euphoria","correct":false,"visible":false},{"text":"Circadian rhythm","correct":true,"visible":false},{"text":"Insomnia","correct":false,"visible":false}]},{"id":116,"text":"Which of the following is an autoimmune disease affecting the nicotinic acetylcholine receptors?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 115.","responses":[{"text":"Guillain-Barré syndrome","correct":false,"visible":false},{"text":"Myasthenia gravis","correct":true,"visible":false},{"text":"Amyotrophic lateral sclerosis","correct":false,"visible":false},{"text":"Duchenne muscular dystrophy (DMD)","correct":false,"visible":false},{"text":"Multiple sclerosis","correct":false,"visible":false}]},{"id":117,"text":"The lower border of septum pellucidum rests upon the upper border of which structure?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 384.","responses":[{"text":"Lentiform nucleus","correct":false,"visible":false},{"text":"Putamen","correct":false,"visible":false},{"text":"Caudate nucleus","correct":false,"visible":false},{"text":"Fornix","correct":true,"visible":false},{"text":"Internal capsule","correct":false,"visible":false}]},{"id":118,"text":"Serotonin or 5-hydroxytryptamine is synthesized from which of the following?","explanation":null,"reference":"Bakshi A, Tadi P. Biochemistry, serotonin. In: StatPearls. StatPearls Publishing; 2022. Accessed March 25, 2022. http://www.ncbi.nlm.nih.gov/books/NBK560856/","responses":[{"text":"Tyrosine","correct":false,"visible":false},{"text":"Tryptophan","correct":true,"visible":false},{"text":"Taurine","correct":false,"visible":false},{"text":"Tri-carboxylic acid","correct":false,"visible":false},{"text":"Tri-acyl glycerol","correct":false,"visible":false}]},{"id":121,"text":"Which one of the following neurotransmitters decreases the pain perception in the brain?","explanation":null,"reference":"Neurotransmitters: the link between depression, chronic fatigue and chronic pain syndromes. Published online March 25, 2022. Accessed March 25, 2022. https://www.bmj.com/content/350/bmj.h1771/rr-12","responses":[{"text":"Cellulose","correct":false,"visible":false},{"text":"Substance P","correct":false,"visible":false},{"text":"Serotonin","correct":true,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Acetylcholine","correct":false,"visible":false}]},{"id":123,"text":"What is the significance of gate control system in pain transmission?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 147.","responses":[{"text":"Basis for relief of pain through rubbing","correct":true,"visible":false},{"text":"For release of dopamine from hypothalamus","correct":false,"visible":false},{"text":"For better pain conduction","correct":false,"visible":false},{"text":"To activate thalamic nuclei","correct":false,"visible":false},{"text":"To increase pain sensation","correct":false,"visible":false}]},{"id":128,"text":"Sympathetic stimulation results in which of the following?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 407.","responses":[{"text":"Constriction of blood vessels in the skin","correct":true,"visible":false},{"text":"Puppillary constriction","correct":false,"visible":false},{"text":"Defecation","correct":false,"visible":false},{"text":"Decreased force of heart contraction","correct":false,"visible":false},{"text":"Increased peristalsis","correct":false,"visible":false}]},{"id":129,"text":"Contralateral hemiparesis in a patient was attributed to a disorder in the internal capsule. What part of the internal capsule is concerned with related tract?","explanation":null,"reference":"Emos MC, Agarwal S. Neuroanatomy, internal capsule. In: StatPearls. StatPearls Publishing; 2022. Accessed March 25, 2022. http://www.ncbi.nlm.nih.gov/books/NBK542181/","responses":[{"text":"Genu","correct":false,"visible":false},{"text":"Posterior limb","correct":true,"visible":false},{"text":"Sublentiform part","correct":false,"visible":false},{"text":"Anterior limb","correct":false,"visible":false},{"text":"Retrolenticular part","correct":false,"visible":false}]},{"id":133,"text":"Which fibers interconnect the two cerebral hemispheres?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 265.","responses":[{"text":"Arcuate fasiciculus","correct":false,"visible":false},{"text":"Stria terminalis","correct":false,"visible":false},{"text":"Fornix","correct":true,"visible":false},{"text":"The cingulum","correct":false,"visible":false},{"text":"Geniculo-calcarine tract","correct":false,"visible":false}]},{"id":139,"text":"Which of the following is a voluntary reflex?","explanation":null,"reference":"Defecation - an overview | sciencedirect topics. Accessed March 29, 2022. https://www.sciencedirect.com/topics/veterinary-science-and-veterinary-medicine/defecation","responses":[{"text":"Flexion of the arm following a painful stimulus","correct":false,"visible":false},{"text":"Defecation","correct":true,"visible":false},{"text":"Acceleration of the heart","correct":false,"visible":false},{"text":"Salivatory secretion","correct":false,"visible":false},{"text":"Micturition","correct":false,"visible":false}]},{"id":142,"text":"Which one of the following, upon release from the nerve terminal, causes the opening of anionic channels in the postsynaptic neuron?","explanation":null,"reference":"Sigel E, Steinmann ME. Structure, function, and modulation of gabaa receptors. The Journal of Biological Chemistry. Published November 23, 2012. Accessed March 25, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3504738/","responses":[{"text":"Glutamate","correct":false,"visible":false},{"text":"Acetylcholine","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Nitric oxide","correct":false,"visible":false},{"text":"GABA","correct":true,"visible":false}]},{"id":144,"text":"Which structure in the CNS acts like valves to pour the cerebrospinal fluid (CSF) into the blood?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 460.","responses":[{"text":"Choroid plexus","correct":false,"visible":false},{"text":"Lymphatic vessels","correct":false,"visible":false},{"text":"Arachnoid villi","correct":true,"visible":false},{"text":"Tela choroidea","correct":false,"visible":false},{"text":"Cerebral arteries","correct":false,"visible":false}]},{"id":146,"text":"Which one of the following is not a feature of a vein of a brain?","explanation":null,"reference":"Hufnagle JJ, Tadi P. Neuroanatomy, brain veins. In: StatPearls. StatPearls Publishing; 2022. Accessed March 25, 2022. http://www.ncbi.nlm.nih.gov/books/NBK546605/","responses":[{"text":"Pierce endosteal layer of dura mater","correct":true,"visible":false},{"text":"No valves","correct":false,"visible":false},{"text":"Pierce arachnoid mater","correct":false,"visible":false},{"text":"No muscular tissue","correct":false,"visible":false},{"text":"Lie in subarachnoid space","correct":false,"visible":false}]},{"id":150,"text":"A young patient after a motorcycle accident was brought into emergency. After investigations, a diagnosis of fracture of the middle cranial fossa was made. The fractured fossa is not formed by which one of the following?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 194.","responses":[{"text":"Petrous part of temporal","correct":false,"visible":false},{"text":"Squamous part of temporal","correct":false,"visible":false},{"text":"Basilar part of occipital","correct":true,"visible":false},{"text":"Greater wing of sphenoid","correct":false,"visible":false},{"text":"Body of sphenoid","correct":false,"visible":false}]},{"id":152,"text":"Which of the following nerve cell bodies is NOT present in the posterior gray column of the spinal cord?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 138.","responses":[{"text":"Phrenic nucleus","correct":true,"visible":false},{"text":"Substantia gelatinosa","correct":false,"visible":false},{"text":"Visceral afferent nucleus","correct":false,"visible":false},{"text":"Nucleus proprius","correct":false,"visible":false},{"text":"Nucleus dorsalis","correct":false,"visible":false}]},{"id":155,"text":"Which of the following elicits inhibitory post synaptic potential?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 62.","responses":[{"text":"Calcium influx","correct":false,"visible":false},{"text":"Sodium influx","correct":false,"visible":false},{"text":"Potassium influx","correct":false,"visible":false},{"text":"Chloride influx","correct":true,"visible":false},{"text":"Bicarbonate influx","correct":false,"visible":false}]},{"id":156,"text":"The majority of afferent fibers in basal ganglia come from which of the following structures?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 319.","responses":[{"text":"Cerebellum","correct":false,"visible":false},{"text":"Motor cortex","correct":true,"visible":false},{"text":"Thalamus","correct":false,"visible":false},{"text":"Associate cortex","correct":false,"visible":false},{"text":"Brain stem","correct":false,"visible":false}]},{"id":157,"text":"What does a 'cobweb' appearance of the CSF indicate?","explanation":null,"reference":"Vinnard C, King L, Munsiff S, et al. Long-term mortality of patients with tuberculous meningitis in new york city: a cohort study. Clinical Infectious Diseases. Published December 7, 2016. Accessed March 25, 2022. https://academic.oup.com/cid/article-lookup/doi/10.1093/cid/ciw763","responses":[{"text":"Tuberculous meningitis","correct":true,"visible":false},{"text":"Acute pyogenic meningitis","correct":false,"visible":false},{"text":"Viral meningitis","correct":false,"visible":false},{"text":"Neurosyphilis","correct":false,"visible":false},{"text":"Viral encephalitis","correct":false,"visible":false}]},{"id":159,"text":"What is the most common type of stroke encountered?","explanation":null,"reference":"Types of Stroke | cdc.gov. Published August 2, 2021. Accessed March 25, 2022. https://www.cdc.gov/stroke/types_of_stroke.htm","responses":[{"text":"Ischemic attack","correct":true,"visible":false},{"text":"Subdural hemorrhage","correct":false,"visible":false},{"text":"Intracerebral hemorrhage","correct":false,"visible":false},{"text":"Metabolic type","correct":false,"visible":false},{"text":"Hemorrhagic attack","correct":false,"visible":false}]},{"id":160,"text":"Which of the following nerve cell groups do not form a part of the auditory pathway?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 212.","responses":[{"text":"Trapezoid body","correct":false,"visible":false},{"text":"Medial geniculate body","correct":false,"visible":false},{"text":"Superior colliculi","correct":true,"visible":false},{"text":"Cochlear nuclei","correct":false,"visible":false},{"text":"Spiral ganglion","correct":false,"visible":false}]},{"id":165,"text":"A picture of the cerebrospinal fluid in acute pyogenic meningitis shows which of the following characteristics?","explanation":null,"reference":"Runde TJ, Anjum F, Hafner JW. Bacterial meningitis. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK470351/","responses":[{"text":"Neutrophils not more than 10,000/cubic mm","correct":false,"visible":false},{"text":"Increased glucose concentration","correct":false,"visible":false},{"text":"Decreased pressure","correct":false,"visible":false},{"text":"Clear fluid","correct":false,"visible":false},{"text":"Increased protein concentration","correct":true,"visible":false}]},{"id":168,"text":"Which structure is not innervated by the nerve emerging from the groove between pons and medulla?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 347, 348.","responses":[{"text":"Buccinator muscle","correct":false,"visible":false},{"text":"Orbicularis oculi","correct":false,"visible":false},{"text":"Sublingual gland","correct":false,"visible":false},{"text":"Lacrimal gland","correct":false,"visible":false},{"text":"Parotid gland","correct":true,"visible":false}]},{"id":170,"text":"A 34-year-old man complains of hemisensory loss and hemiparesis of the leg and foot of the contralateral side of the body. He also has difficulty in identifying objects and has developed personality changes. His MRI shows a compromised area with reduced blood supply. Which artery is responsible for these losses?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 472.","responses":[{"text":"Anterior spinal artery","correct":false,"visible":false},{"text":"Posterior cerebral artery","correct":false,"visible":false},{"text":"Middle cerebral artery","correct":false,"visible":false},{"text":"Anterior cerebral artery","correct":true,"visible":false},{"text":"Posterior inferior cerebellar artery","correct":false,"visible":false}]},{"id":173,"text":"Thermal nociceptors are activated by skin temperature above what value?","explanation":null,"reference":"Qin F. Time-resolved activation of thermal trp channels by fast temperature jumps. In: Zhu MX, ed. TRP Channels. CRC Press/Taylor \u0026 Francis; 2011. Accessed March 27, 2022. http://www.ncbi.nlm.nih.gov/books/NBK92811/","responses":[{"text":"20 celsius","correct":false,"visible":false},{"text":"11 celsius","correct":false,"visible":false},{"text":"13 celsius","correct":false,"visible":false},{"text":"45 celsius","correct":true,"visible":false},{"text":"29 celsius","correct":false,"visible":false}]},{"id":181,"text":"Which of the following tract is concerned with voluntary discrete and skilled movements, especially of distal parts of limbs?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 162.","responses":[{"text":"Tectospinal tract","correct":false,"visible":false},{"text":"Reticulospinal tract","correct":false,"visible":false},{"text":"Ruberospinal tract","correct":false,"visible":false},{"text":"Corticospinal tract","correct":true,"visible":false},{"text":"Vestibulospinal tract","correct":false,"visible":false}]},{"id":183,"text":"Weber syndrome is caused by the occlusion of a branch of which artery?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 217.","responses":[{"text":"Posterior inferior cerebellar artery","correct":false,"visible":false},{"text":"Posterior cerebral artery","correct":true,"visible":false},{"text":"Anterior inferior cerebellar artery","correct":false,"visible":false},{"text":"Superior cerebellar artery","correct":false,"visible":false},{"text":"Basilar artery","correct":false,"visible":false}]},{"id":185,"text":"Which cranial nerve motor nuclei are present in the pons?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 520.","responses":[{"text":"I and II","correct":false,"visible":false},{"text":"IX, X, and XII","correct":false,"visible":false},{"text":"VIII","correct":false,"visible":false},{"text":"III and IV","correct":false,"visible":false},{"text":"V, VI, and VII","correct":true,"visible":false}]},{"id":186,"text":"Which of the following characterizes upper motor neuron lesions?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 166.","responses":[{"text":"Fasiculations","correct":false,"visible":false},{"text":"Disuse atrophy","correct":true,"visible":false},{"text":"Hypoactive muscle stretch reflex","correct":false,"visible":false},{"text":"Decreased muscle tone","correct":false,"visible":false},{"text":"Flaccid paralysis","correct":false,"visible":false}]},{"id":188,"text":"Which of the following is not a feature of meperidine?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 572.","responses":[{"text":"It produces mydriasis","correct":false,"visible":false},{"text":"It is a synthetic compound","correct":false,"visible":false},{"text":"It produces miosis","correct":true,"visible":false},{"text":"It has no antitussive effect","correct":false,"visible":false},{"text":"It can cause convulsions in large doses","correct":false,"visible":false}]},{"id":190,"text":"Which of the following chemical neurotransmitters are present in neurons that have cell bodies in the brainstem projecting to the hypothalamus, limbic system, neocortex, cerebellum, and spinal cord?","explanation":null,"reference":"Tryptophan hydroxylase 2 - an overview | sciencedirect topics. Accessed March 29, 2022. https://www.sciencedirect.com/topics/pharmacology-toxicology-and-pharmaceutical-science/tryptophan-hydroxylase-2","responses":[{"text":"Serotonin","correct":true,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Dopa","correct":false,"visible":false}]},{"id":192,"text":"Which one of the following cranial nerves emerges from the dorsal aspect of the midbrain?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 340.","responses":[{"text":"Facial","correct":false,"visible":false},{"text":"Trochlear","correct":true,"visible":false},{"text":"Occulomotor","correct":false,"visible":false},{"text":"Abducent","correct":false,"visible":false},{"text":"Trigeminal","correct":false,"visible":false}]},{"id":227,"text":"What is the approximate pH of anaerobically collected cerebrospinal fluid?","explanation":null,"reference":"Cerebrospinal fluid ph - an overview | sciencedirect topics. Accessed March 29, 2022. https://www.sciencedirect.com/topics/biochemistry-genetics-and-molecular-biology/cerebrospinal-fluid-ph","responses":[{"text":"7.10","correct":false,"visible":false},{"text":"7.31","correct":true,"visible":false},{"text":"7.15","correct":false,"visible":false},{"text":"7.01","correct":false,"visible":false},{"text":"7.20","correct":false,"visible":false}]},{"id":228,"text":"Surgery was planned for a 14-year-old student for his atrial septal defect. On the day of his surgery, he was very anxious. The doctor examined his eyes with an ophthalmoscope and subsequently gave him anxiolytics for his nervousness. Contraction of which of the following eye muscles is the result of the sympathetic effect of anxiety?","explanation":null,"reference":"Sánchez-de la Torre JR, Drake-Pérez M, Casado A, et al. Persistent isolated mydriasis as an early sign of internal carotid artery dissection: Pourfour du petit syndrome. Clinical Neurology and Neurosurgery. Published July 1, 2019. Accessed March 29, 2022. https://www.sciencedirect.com/science/article/pii/S0303846719301337","responses":[{"text":"Longitudinal muscles causing miosis","correct":false,"visible":false},{"text":"Constrictor pupillae causing miosis","correct":false,"visible":false},{"text":"Dilator pupillae causing miosis","correct":false,"visible":false},{"text":"Dilator pupillae causing mydriasis","correct":true,"visible":false},{"text":"Constrictor pupillae causing mydriasis","correct":false,"visible":false}]},{"id":229,"text":"On ultrasonography, the amniotic fluid around the embryo seems to be in excess. The cavity containing this fluid is lined by cells derived from which of the following?","explanation":null,"reference":"Amniotic cavity development movie - embryology. Accessed March 29, 2022. https://embryology.med.unsw.edu.au/embryology/index.php/Amniotic_Cavity_Development_Movie","responses":[{"text":"Hypoblast","correct":false,"visible":false},{"text":"Cytotrophoblast","correct":false,"visible":false},{"text":"Epiblast","correct":true,"visible":false},{"text":"Syncytiotrophoblast","correct":false,"visible":false},{"text":"Extraembryonic mesoderm","correct":false,"visible":false}]},{"id":230,"text":"Mr. Arshad, a 45-year-old diabetic man, is referred to the surgical unit for the dressing of a wound on the sole of his left foot. He says that when he took his shoes off at night there was a small stone inside the shoe which had wounded the foot, making it bleed. However, surprisingly, he did not feel pain at all. Conscious perception of this sensation is most likely carried by which one of the following tracts?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 143.","responses":[{"text":"Spinocerebellar tract","correct":false,"visible":false},{"text":"Anterior spinothalamic tract","correct":false,"visible":false},{"text":"Dorsal column medial lemniscus system","correct":false,"visible":false},{"text":"Corticospinal tract","correct":false,"visible":false},{"text":"Lateral spinothalamic tract","correct":true,"visible":false}]},{"id":231,"text":"What is the central metabolite of norepinephrine?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 83.","responses":[{"text":"Vanillylmandelic acid (VMA)","correct":true,"visible":false},{"text":"Gamma-aminobutyric acid","correct":false,"visible":false},{"text":"Homovallinic acid (HVA)","correct":false,"visible":false},{"text":"5-Hydroxyindoleacetic acid (5-HIAA)","correct":false,"visible":false},{"text":"3-Methoxy-4-hydroxyphenylglycol (MHPG)","correct":false,"visible":false}]},{"id":232,"text":"A 65-year-old man came to the outpatient department. Physical examination revealed that his eyeball deviated laterally because of paralysis of the medial rectus muscle, with the pupil dilated and loss of accommodation. Which structure of the brain is involved?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 560.","responses":[{"text":"Pons","correct":false,"visible":false},{"text":"Oculomotor nerve","correct":true,"visible":false},{"text":"Mid brain","correct":false,"visible":false},{"text":"Medulla oblongata","correct":false,"visible":false},{"text":"Trochlear nerve","correct":false,"visible":false}]},{"id":233,"text":"L-DOPA is converted to dopamine by which of the following enzymes?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 569.","responses":[{"text":"DOPA hydroxylase","correct":false,"visible":false},{"text":"DOPA reductase","correct":false,"visible":false},{"text":"DOPA carboxylase","correct":false,"visible":false},{"text":"DOPA oxidase","correct":false,"visible":false},{"text":"DOPA decarboxylase","correct":true,"visible":false}]},{"id":234,"text":"Damage to the basal ganglia occurs in Parkinson's disease. Which of the following tremors is present in the disease?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 323.","responses":[{"text":"Resting tremors","correct":true,"visible":false},{"text":"Flapping tremors","correct":false,"visible":false},{"text":"Intention tremors","correct":false,"visible":false},{"text":"Fine tremors","correct":false,"visible":false},{"text":"Voluntary tremors","correct":false,"visible":false}]},{"id":235,"text":"Which one of the following is the structural precursor molecule of sphingolipids?","explanation":null,"reference":"Kitatani K, Idkowiak-Baldys J, Hannun YA. The sphingolipid salvage pathway in ceramide metabolism and signaling. Cellular signalling. Published June 2008. Accessed March 29, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2422835/","responses":[{"text":"Ceramide","correct":true,"visible":false},{"text":"Palmityl CoA","correct":false,"visible":false},{"text":"Cellulose","correct":false,"visible":false},{"text":"Inulin","correct":false,"visible":false},{"text":"Glycerol","correct":false,"visible":false}]},{"id":236,"text":"Which receptors receive stimuli immediate from external surroundings?","explanation":null,"reference":"Marzvanyan A, Alhawaj AF. Physiology, sensory receptors. In: StatPearls. StatPearls Publishing; 2022. Accessed March 27, 2022. http://www.ncbi.nlm.nih.gov/books/NBK539861/","responses":[{"text":"Proprioreceptors","correct":false,"visible":false},{"text":"Chemoreceptors","correct":false,"visible":false},{"text":"Exteroreceptors","correct":true,"visible":false},{"text":"Enteroreceptors","correct":false,"visible":false},{"text":"Teloreceptors","correct":false,"visible":false}]},{"id":237,"text":"A 70-year-old man has a 2-day history of a generalized, progressively worsening headache and increasing obtundation. He now complains of stiffness in his neck. On physical examination, vital signs include a temperature of 37°C, a pulse of 85/minute, respiration 23/minute, and blood pressure 130/85 mm Hg. A CBC reveals a WBC count of 16,850/microliter. A lumbar puncture yields cloudy cerebrospinal fluid with raised glucose, decreased protein, cell count of 3800 WBCs (95% polymorphonuclear leukocytes (PMNs) and 5% mononuclear), and 122 RBCs. He receives antibiotic therapy and improves. Which of the following is the most likely long-term complication from this man's current disease?","explanation":null,"reference":"Hersi K, Gonzalez F, Kondamudi N. Meningitis. StatPearls. Published online November 7, 2021. Accessed March 29, 2022. https://www.statpearls.com/articlelibrary/viewarticle/24962/","responses":[{"text":"Hydrocephalus","correct":true,"visible":false},{"text":"Encephalitis","correct":false,"visible":false},{"text":"Subdural hematoma","correct":false,"visible":false},{"text":"Tonsillar herniation","correct":false,"visible":false},{"text":"Cerebellar herniation","correct":false,"visible":false}]},{"id":238,"text":"An 8-month-old baby is brought to the pediatric emergency with a history of high-grade fever, fits, and refusal to take feed. On examination, he has a 102 °F temperature with altered consciousness. On cerebrospinal fluid (CSF) examination, cells are 1200/ml and mostly polymorphonuclear neutrophils. Which type of meningitis is it most likely to be?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 180.","responses":[{"text":"Viral meningitis","correct":false,"visible":false},{"text":"Bacterial meningitis","correct":true,"visible":false},{"text":"Aspetic meningitis","correct":false,"visible":false},{"text":"Subacute meningitis","correct":false,"visible":false},{"text":"Tuberculous meningitis","correct":false,"visible":false}]},{"id":239,"text":"The binding of acetylcholine to its nicotinic receptor increases the permeability of the cell membrane to which one of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 91.","responses":[{"text":"Ca++","correct":false,"visible":false},{"text":"K+","correct":false,"visible":false},{"text":"Cl−","correct":false,"visible":false},{"text":"Na+","correct":true,"visible":false},{"text":"Se+","correct":false,"visible":false}]},{"id":240,"text":"A 38-year-old patient comes to the outpatient department with the complaint of shaking hands while buttoning clothes, writing, or shaving. The doctor asked him to stand still with his eyes closed and noted a negative Romberg test. Vibration senses are normal in all of the four limbs on examination. Based on the clinical picture, which area is most likely to be damaged?","explanation":null,"reference":"Forbes J, Cronovich H. Romberg test. In: StatPearls. StatPearls Publishing; 2022. Accessed March 29, 2022. http://www.ncbi.nlm.nih.gov/books/NBK563187/","responses":[{"text":"Cerebral peduncles","correct":false,"visible":false},{"text":"Cerebellum","correct":true,"visible":false},{"text":"Dorsal column","correct":false,"visible":false},{"text":"Ventral horns of spinal cord","correct":false,"visible":false},{"text":"Posterior limb of internal capsule","correct":false,"visible":false}]},{"id":241,"text":"Which one of the following forms the blood-brain barrier?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 453.","responses":[{"text":"Neurons","correct":false,"visible":false},{"text":"Smooth muscle cells","correct":false,"visible":false},{"text":"Hepatocytes","correct":false,"visible":false},{"text":"Astrocytes","correct":true,"visible":false},{"text":"Osteocytes","correct":false,"visible":false}]},{"id":243,"text":"Gracilis and cuneatus tubercles are seen on the surface of which of the following?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 198.","responses":[{"text":"Medulla oblongata","correct":true,"visible":false},{"text":"Pons","correct":false,"visible":false},{"text":"Cerebellum","correct":false,"visible":false},{"text":"Spinal cord","correct":false,"visible":false},{"text":"Mid brain","correct":false,"visible":false}]},{"id":244,"text":"Stimulation of the lateral hypothalamus causes an animal to develop which of the following?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 391.","responses":[{"text":"Fear","correct":false,"visible":false},{"text":"Tranquility","correct":false,"visible":false},{"text":"Rage","correct":true,"visible":false},{"text":"Decreased eating","correct":false,"visible":false},{"text":"Calmness","correct":false,"visible":false}]},{"id":245,"text":"The nuclear bag fibers of muscle spindles are innervated by which of the following sensory afferent fibers?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 591.","responses":[{"text":"Aγ fibers","correct":false,"visible":false},{"text":"A𝛿 fibers","correct":false,"visible":false},{"text":"Ia fibers","correct":true,"visible":false},{"text":"Ib fibers","correct":false,"visible":false},{"text":"Aβ fibers","correct":false,"visible":false}]},{"id":246,"text":"The most severe form of cranial neural tube defects (NTD) is characterized by: 1) major portions of the cranium and intracranial structures being absent, 2) orbits and face being present (bulging eyes) 3) polyhydramnios 4) macroglossia 5) very short neck. What type of neural tube defect is this likely to be?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 505.","responses":[{"text":"Meningitis","correct":false,"visible":false},{"text":"Anencephaly","correct":true,"visible":false},{"text":"Encephalocele","correct":false,"visible":false},{"text":"Acrania","correct":false,"visible":false},{"text":"Iniencephaly","correct":false,"visible":false}]},{"id":248,"text":"Hypothalamus releases which of the following substances to induce wakefulness?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 591.","responses":[{"text":"Acetylcholine","correct":false,"visible":false},{"text":"Adrenaline","correct":false,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Orexin","correct":true,"visible":false},{"text":"Muramyl peptide","correct":false,"visible":false}]},{"id":251,"text":"A patient comes with a lenticulostriate artery block due to chronic hypertension. Which of the following structures is supplied by it?","explanation":null,"reference":"White J, Seiden D. USMLE® Step 1 Lecture Notes 2019: Anatomy. Kaplan Medical; 2019: 387.","responses":[{"text":"Anterior limb of internal capsule","correct":false,"visible":false},{"text":"Whole internal capsule","correct":false,"visible":false},{"text":"Inferior limb of internal capsule","correct":false,"visible":false},{"text":"Posterior limb of internal capsule","correct":true,"visible":false},{"text":"Both anterior and inferior limb of internal capsule","correct":false,"visible":false}]},{"id":256,"text":"A child is having a tickling sensation. Which tract would be involved?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 144.","responses":[{"text":"Dorsal spinothalamic","correct":false,"visible":false},{"text":"Anterior spinothalamic","correct":true,"visible":false},{"text":"Pontomedullary","correct":false,"visible":false},{"text":"Anterior spinocerebellar","correct":false,"visible":false},{"text":"Lateral spinothalamic","correct":false,"visible":false}]},{"id":258,"text":"Damage to which part of the brain results in a condition called athetosis?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 318.","responses":[{"text":"Subthalamus","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Caudate","correct":false,"visible":false},{"text":"Globus pallidus","correct":true,"visible":false},{"text":"Putamen","correct":false,"visible":false}]},{"id":259,"text":"Which one of the following are the most sensitive cells of the central nervous system?","explanation":null,"reference":"Central nervous system neurons - an overview | sciencedirect topics. Accessed March 29, 2022. https://www.sciencedirect.com/topics/neuroscience/central-nervous-system-neurons","responses":[{"text":"Renshaw cells","correct":false,"visible":false},{"text":"Astrocytes","correct":false,"visible":false},{"text":"Microglial cells","correct":false,"visible":false},{"text":"Neurons","correct":true,"visible":false},{"text":"Schwann cells","correct":false,"visible":false}]},{"id":261,"text":"A patient comes to the neurology department with a complaint of dryness of the mouth and irritation in the eyes. It is diagnosed that there is a lesion in the lacrimal and salivary glands. Which of the nerves is most likely to get affected?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 348.","responses":[{"text":"Trochlear nerve","correct":false,"visible":false},{"text":"Vagus nerve","correct":false,"visible":false},{"text":"Oculomotor nerve","correct":false,"visible":false},{"text":"Facial nerve","correct":true,"visible":false},{"text":"Glossopharyngeal nerve","correct":false,"visible":false}]},{"id":262,"text":"What is the biologically active amine form of phenylalanine?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 285.","responses":[{"text":"Valine","correct":false,"visible":false},{"text":"Dopamine","correct":true,"visible":false},{"text":"Tyrosine","correct":false,"visible":false},{"text":"Tryptamine","correct":false,"visible":false},{"text":"Taurine","correct":false,"visible":false}]},{"id":263,"text":"During lumbar puncture, where is the cerebrospinal fluid withdrawn from?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 19.","responses":[{"text":"Ventricles","correct":false,"visible":false},{"text":"Subarachnoid and subdural space","correct":false,"visible":false},{"text":"Central canal","correct":false,"visible":false},{"text":"Subdural space","correct":false,"visible":false},{"text":"Subarachnoid space","correct":true,"visible":false}]},{"id":264,"text":"What is the total volume of cerebrospinal fluid present in the central nervous system?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 458.","responses":[{"text":"15 ml","correct":false,"visible":false},{"text":"150 ml","correct":true,"visible":false},{"text":"50 ml","correct":false,"visible":false},{"text":"100 ml","correct":false,"visible":false},{"text":"250 ml","correct":false,"visible":false}]},{"id":265,"text":"Electrical recordings from the surface of the head demonstrate that there is continuous electrical activity in the brain which can be recorded in the form of multiple waves. One of these waves is an alpha wave. Which area of the brain does it originate from?","explanation":null,"reference":"Thalamic mechanisms of eeg alpha rhythms and their pathological implications | request pdf. ResearchGate. Accessed March 28, 2022. https://www.researchgate.net/publication/7685428_Thalamic_Mechanisms_of_EEG_Alpha_Rhythms_and_Their_Pathological_Implications","responses":[{"text":"Epithalamus","correct":false,"visible":false},{"text":"Thalamocortical system","correct":true,"visible":false},{"text":"Cerebral cortex","correct":false,"visible":false},{"text":"Cerebellocortical system","correct":false,"visible":false},{"text":"Pontocerebellar connection system","correct":false,"visible":false}]},{"id":266,"text":"A patient comes to the neurology department with a complaint of loss of fine touch in his right upper limb. He is also unable to feel the vibration of his phone. The patient also states that he had a roadside accident a few days back. Which tract is affected?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 149.","responses":[{"text":"Anterior spinocerebellar","correct":false,"visible":false},{"text":"Posterior spinocerebellar","correct":false,"visible":false},{"text":"Dorsal column–medial lemniscus pathway","correct":true,"visible":false},{"text":"Lateral spinothalamic tract","correct":false,"visible":false},{"text":"Anterior spinothalamic tract","correct":false,"visible":false}]},{"id":267,"text":"Which of the following does the vestibulocochlear nerve pass through?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 350.","responses":[{"text":"Internal auditory meatus","correct":true,"visible":false},{"text":"Foramen ovale","correct":false,"visible":false},{"text":"Foramen spinosum","correct":false,"visible":false},{"text":"Foramen rotundum","correct":false,"visible":false},{"text":"Jugular foramen","correct":false,"visible":false}]},{"id":269,"text":"Absence of alpha waves indicates damage to which tract?","explanation":null,"reference":"Alpha rhythm - an overview | sciencedirect topics. Accessed March 26, 2022. https://www.sciencedirect.com/topics/nursing-and-health-professions/alpha-rhythm","responses":[{"text":"Pontomedullary fibers","correct":false,"visible":false},{"text":"Hypothalamus","correct":false,"visible":false},{"text":"Thalamocortical fibers","correct":true,"visible":false},{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Corticospinal fibers","correct":false,"visible":false}]},{"id":270,"text":"A student is studying intracerebellar lesions and wants to find out what nucleus is involved if there is a lesion in the vermis. Which nucleus is involved in this lesion?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 235.","responses":[{"text":"Dentate","correct":false,"visible":false},{"text":"Fastigial","correct":true,"visible":false},{"text":"Emboliform","correct":false,"visible":false},{"text":"Clarke","correct":false,"visible":false},{"text":"Globose","correct":false,"visible":false}]},{"id":271,"text":"What is the inability to perform alternating movements known as?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 244.","responses":[{"text":"Dysdiadochokinesia","correct":true,"visible":false},{"text":"Athetosis","correct":false,"visible":false},{"text":"Hyporeflexia","correct":false,"visible":false},{"text":"Chorea","correct":false,"visible":false},{"text":"Hemiballismus","correct":false,"visible":false}]},{"id":273,"text":"Human chorionic gonadotropin (HCG) in a woman's blood indicates pregnancy. It is secreted by which one of the following?","explanation":null,"reference":"Betz D, Fane K. Human chorionic gonadotropin. In: StatPearls. StatPearls Publishing; 2022. Accessed March 28, 2022. http://www.ncbi.nlm.nih.gov/books/NBK532950/","responses":[{"text":"Syncytiotrophoblast","correct":true,"visible":false},{"text":"Placenta","correct":false,"visible":false},{"text":"Epiblast","correct":false,"visible":false},{"text":"Hypoblast","correct":false,"visible":false},{"text":"Cytotrophoblast","correct":false,"visible":false}]},{"id":275,"text":"Which structure is present deep in the lateral sulcus?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 256.","responses":[{"text":"Secondary motor cortex","correct":false,"visible":false},{"text":"Primary motor cortex","correct":false,"visible":false},{"text":"Primary sensory cortex","correct":false,"visible":false},{"text":"Supplementary motor area","correct":false,"visible":false},{"text":"Insula","correct":true,"visible":false}]},{"id":277,"text":"Which nuclei of the hypothalamus are connected to the posterior pituitary gland?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 388.","responses":[{"text":"Arcuate and preoptic","correct":false,"visible":false},{"text":"Supraoptic and paraventricular","correct":true,"visible":false},{"text":"ventromedial and paraventricular","correct":false,"visible":false},{"text":"Lateral hypothalamic and ventromedial","correct":false,"visible":false},{"text":"Supraoptic and preoptic","correct":false,"visible":false}]},{"id":278,"text":"What does the ventromedial nucleus of the hypothalamus control?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 390.","responses":[{"text":"Hunger","correct":false,"visible":false},{"text":"Circadian rhythm","correct":false,"visible":false},{"text":"Water balance","correct":false,"visible":false},{"text":"Temperature","correct":false,"visible":false},{"text":"Satiety","correct":true,"visible":false}]},{"id":280,"text":"Where does the trochlear nerve emerge from?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 340.","responses":[{"text":"Superior surface of midbrain","correct":false,"visible":false},{"text":"Posterior surface of midbrain","correct":true,"visible":false},{"text":"Anterior surface of midbrain","correct":false,"visible":false},{"text":"Inferior surface of midbrain","correct":false,"visible":false},{"text":"Lateral surface of midbrain","correct":false,"visible":false}]},{"id":281,"text":"Which one of the following is an inhibitory cell in the spinal cord?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 164.","responses":[{"text":"Renshaw cells","correct":true,"visible":false},{"text":"Granule cells","correct":false,"visible":false},{"text":"Amacrine cells","correct":false,"visible":false},{"text":"Purkinje cells","correct":false,"visible":false},{"text":"Muller cells","correct":false,"visible":false}]},{"id":283,"text":"A 50-year-old patient presents with tuberculous meningitis for the past 10 years. Which of the following is most likely to be his viral history?","explanation":null,"reference":"Slane VH, Unakal CG. Tuberculous meningitis. In: StatPearls. StatPearls Publishing; 2022. Accessed March 28, 2022. http://www.ncbi.nlm.nih.gov/books/NBK541015/","responses":[{"text":"Hepatitis C","correct":false,"visible":false},{"text":"Human immunodeficiency virus (HIV)","correct":true,"visible":false},{"text":"Herpes simplex virus (HSV)","correct":false,"visible":false},{"text":"Hepatitis A","correct":false,"visible":false},{"text":"Hepatitis B","correct":false,"visible":false}]},{"id":285,"text":"Which of the following receptors detects pressure?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 570.","responses":[{"text":"Meissner's corpuscle","correct":false,"visible":false},{"text":"Pacinian corpsule","correct":true,"visible":false},{"text":"Merkel's disc","correct":false,"visible":false},{"text":"Free nerve ending","correct":false,"visible":false},{"text":"Krause end bulb","correct":false,"visible":false}]},{"id":286,"text":"Nitric oxide (NO) is one of the neurotransmitters that cause vasodilation. Which of the following is correct regarding nitric oxide?","explanation":null,"reference":"Picón-Pagès P, Garcia-Buendia J, Muñoz FJ. Functions and dysfunctions of nitric oxide in brain. Biochimica et Biophysica Acta (BBA) - Molecular Basis of Disease. Published August 1, 2019. Accessed March 28, 2022. https://www.sciencedirect.com/science/article/pii/S0925443918304526","responses":[{"text":"Catecholamine derivative","correct":false,"visible":false},{"text":"Glutamate derivative","correct":false,"visible":false},{"text":"Gaseous neurotransmitter","correct":true,"visible":false},{"text":"Glycine derivative","correct":false,"visible":false},{"text":"Peptide derivative","correct":false,"visible":false}]},{"id":289,"text":"A patient presents to the clinic. He is diagnosed with chronic meningitis and has acquired immunodeficiency syndrome (AIDS) for the past 14 years. Which organism is the most likely cause for this?","explanation":null,"reference":"Akram SM, Attia FN. Mycobacterium avium intracellulare. In: StatPearls. StatPearls Publishing; 2022. Accessed March 28, 2022. http://www.ncbi.nlm.nih.gov/books/NBK431110/","responses":[{"text":"Toxoplasma gondii","correct":false,"visible":false},{"text":"Candida albicans","correct":false,"visible":false},{"text":"Mycobacterium marinum","correct":false,"visible":false},{"text":"Mycobacterium scrofulaceum","correct":false,"visible":false},{"text":"Mycobacterium avium intracellulare","correct":true,"visible":false}]},{"id":291,"text":"Which of the essential amino acids is used to synthesize L-DOPA?","explanation":null,"reference":"Selfdecode | genome analysis. SelfDecode.com. Accessed March 28, 2022. https://selfdecode.com/chemical/l-phenylalanine/","responses":[{"text":"Linolenic acid","correct":false,"visible":false},{"text":"Linoleic acid","correct":false,"visible":false},{"text":"Phenylalanine","correct":true,"visible":false},{"text":"Arachidonic acid","correct":false,"visible":false},{"text":"Tyrosine","correct":false,"visible":false}]},{"id":295,"text":"Somatosensory information relays in which nucleus of thalamus?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 374.","responses":[{"text":"Mediodorsal nucleus","correct":false,"visible":false},{"text":"Ventroposteriolateral nucleus","correct":true,"visible":false},{"text":"Ventro lateral nucleus","correct":false,"visible":false},{"text":"Anterior nuclear","correct":false,"visible":false},{"text":"Ventro anterior nucleus","correct":false,"visible":false}]},{"id":296,"text":"A research student is given a task to find out the results of electrical stimulation of different parts of the hypothalamus of a rat. On stimulation of the anterior hypothalamic area and preoptic area, what response is likely to be seen?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 390.","responses":[{"text":"Sympathetic response","correct":false,"visible":false},{"text":"Cessation of peristalsis","correct":false,"visible":false},{"text":"Pupillary dilation","correct":false,"visible":false},{"text":"Parasympathetic response","correct":true,"visible":false},{"text":"Elevation of blood pressure","correct":false,"visible":false}]},{"id":298,"text":"Which one of the following is involved in the anticipation of postural equilibrium?","explanation":null,"reference":"Flocculonodular lobe - an overview | sciencedirect topics. Accessed March 28, 2022. https://www.sciencedirect.com/topics/neuroscience/flocculonodular-lobe","responses":[{"text":"Primary sensory area","correct":false,"visible":false},{"text":"Spinocerebellum","correct":false,"visible":false},{"text":"Premotor area","correct":false,"visible":false},{"text":"Vestibulocerebellum","correct":true,"visible":false},{"text":"Cerebrocerebellum","correct":false,"visible":false}]},{"id":299,"text":"Which of the following is incorrect about the cells of the cerebellar cortex?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 231, 232, 233.","responses":[{"text":"Purkinje cells in middle purkinje layer","correct":false,"visible":false},{"text":"Granules cells in inner granular layer","correct":false,"visible":false},{"text":"Basket cell in outer molecular layer","correct":false,"visible":false},{"text":"Stellate cells in granular layer","correct":true,"visible":false},{"text":"Golgi cells in inner granular layer","correct":false,"visible":false}]},{"id":300,"text":"About the myelin sheath of the peripheral nerve, which of the following is correct?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 71.","responses":[{"text":"In the central nervous system, myelinating cells myelinate several internodes of different axons","correct":false,"visible":false},{"text":"It is produced by Schwann cells","correct":true,"visible":false},{"text":"It is produced by oligodendrocytes","correct":false,"visible":false},{"text":"It is produced by microglia","correct":false,"visible":false},{"text":"In the peripheral nervous system, myelinating cell myelinate only one internode","correct":false,"visible":false}]},{"id":303,"text":"Regarding myelination in peripheral nervous system, what is the correct statement?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 71.","responses":[{"text":"Myelinating fibers have slow conduction velocity","correct":false,"visible":false},{"text":"It is also produced by fibroblasts as well","correct":false,"visible":false},{"text":"It is produced by Schwann cells","correct":true,"visible":false},{"text":"A Schwann cell can myelinate upto 30 axons","correct":false,"visible":false},{"text":"Oligodendrocytes are myelinating cells of peripheral nervous system","correct":false,"visible":false}]},{"id":304,"text":"Regarding myelin sheath around axons, what is correct?","explanation":null,"reference":"Fallon M, Tadi P. Histology, schwann cells. In: StatPearls. StatPearls Publishing; 2022. Accessed March 27, 2022. http://www.ncbi.nlm.nih.gov/books/NBK544316/","responses":[{"text":"Myelin sheath is proportional to the diameter of axon","correct":false,"visible":false},{"text":"Neurons in peripheral nervous system is myelinated by oligodendrocytes","correct":false,"visible":false},{"text":"Starts developing in fetal life and continues till one year","correct":true,"visible":false},{"text":"Formed by astrocytes in brain","correct":false,"visible":false},{"text":"Nodes of ranvier are not present in CNS","correct":false,"visible":false}]},{"id":305,"text":"Where are the cell bodies of postganglionic neurons of parasympathetic fibers located?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 387, 388, 389.","responses":[{"text":"Cell bodies in central nervous system","correct":false,"visible":false},{"text":"Sympathetic trunk","correct":false,"visible":false},{"text":"Autonomic ganglia in pelvis","correct":false,"visible":false},{"text":"Ganglion in the visceral walls","correct":true,"visible":false},{"text":"Autonomic ganglia in abdomen","correct":false,"visible":false}]},{"id":306,"text":"Which of the following will not result with stimulation of periventricular and lateral nuclei of the hypothalamus?","explanation":null,"reference":"Hall JE. Guyton and Hall Textbook of Medical Physiology. 13th ed. Elsevier; 2016: 757, 758.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Thirst","correct":false,"visible":false},{"text":"Feeling of rage","correct":false,"visible":false},{"text":"Decreased appetite","correct":true,"visible":false},{"text":"Increased appetite","correct":false,"visible":false}]},{"id":307,"text":"About the axons of the peripheral nerve, which of the following is incorrect?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 163.","responses":[{"text":"It may arise from axon hillock","correct":false,"visible":false},{"text":"It transmits action potential","correct":false,"visible":false},{"text":"It may arise from the perikyon (Soma)","correct":false,"visible":false},{"text":"It may arise from a dendrite","correct":false,"visible":false},{"text":"It contains nissl substance","correct":true,"visible":false}]},{"id":308,"text":"Where does absorption of cerebrospinal fluid occur?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 435.","responses":[{"text":"Epidural space","correct":false,"visible":false},{"text":"Arachnoid villi","correct":true,"visible":false},{"text":"3rd ventricle","correct":false,"visible":false},{"text":"Lateral ventricle","correct":false,"visible":false},{"text":"Aqueduct of Sylvius","correct":false,"visible":false}]},{"id":311,"text":"Damage to which of the following results in lesion of the oculomotor nerve nucleus in the midbrain?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 220.","responses":[{"text":"Posterior cerebral artery","correct":true,"visible":false},{"text":"Basilar artery","correct":false,"visible":false},{"text":"Anterior cerebral artery","correct":false,"visible":false},{"text":"Middle cerebral artery","correct":false,"visible":false},{"text":"Vertebral artery","correct":false,"visible":false}]},{"id":312,"text":"Which of the following is an ascending tract in the posterior white column?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 149.","responses":[{"text":"Spino-olivary tract","correct":false,"visible":false},{"text":"Fasciculus gracilis tract","correct":true,"visible":false},{"text":"Anterior spinocerebellar tract","correct":false,"visible":false},{"text":"Lateral spinothalamic tract","correct":false,"visible":false},{"text":"Posterior spinocerebellar tract","correct":false,"visible":false}]},{"id":314,"text":"Which of the following sensations is detected by nociceptors?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 587.","responses":[{"text":"Pain","correct":true,"visible":false},{"text":"Temperature","correct":false,"visible":false},{"text":"Vibration","correct":false,"visible":false},{"text":"Taste","correct":false,"visible":false},{"text":"Pressure","correct":false,"visible":false}]},{"id":318,"text":"Which is NOT true about Betz cells?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 282.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"They are present in the 6th layer of cerebral cortex","correct":true,"visible":false},{"text":"They are present in the 5th layer of cerebral cortex","correct":false,"visible":false},{"text":"Their axons pass to the spinal cord as corticospinal fibers","correct":false,"visible":false},{"text":"Largest cells of the central nervous system","correct":false,"visible":false}]},{"id":322,"text":"Where does the cerebellum receive information concerning muscle movement from?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 240.","responses":[{"text":"Caudate","correct":false,"visible":false},{"text":"Putamen","correct":false,"visible":false},{"text":"Macula","correct":false,"visible":false},{"text":"Proprioceptors","correct":true,"visible":false},{"text":"Basal ganglia","correct":false,"visible":false}]},{"id":327,"text":"What is the rate of formation of cerebrospinal fluid?","explanation":null,"reference":"Sakka L, Coll G, Chazal J. Anatomy and physiology of cerebrospinal fluid. European Annals of Otorhinolaryngology, Head and Neck Diseases. Published December 1, 2011. Accessed March 25, 2022. https://www.sciencedirect.com/science/article/pii/S1879729611001013","responses":[{"text":"100 millilitre/each day","correct":false,"visible":false},{"text":"1000 millilitre/each day","correct":false,"visible":false},{"text":"2000 millilitre/each day","correct":false,"visible":false},{"text":"10 millilitre/each day","correct":false,"visible":false},{"text":"500 millilitre/each day","correct":true,"visible":false}]},{"id":331,"text":"Which of the following secretes cerebrospinal fluid?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 60.","responses":[{"text":"Dura mater","correct":false,"visible":false},{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Pia mater","correct":false,"visible":false},{"text":"Thalamus","correct":false,"visible":false},{"text":"Choroid plexus","correct":true,"visible":false}]},{"id":332,"text":"Which of the following tracts starts from the red nucleus, decussates in the midline, and descends down?","explanation":null,"reference":"Lee J, Muzio MR. Neuroanatomy, extrapyramidal system. In: StatPearls. StatPearls Publishing; 2022. Accessed March 26, 2022. http://www.ncbi.nlm.nih.gov/books/NBK554542/","responses":[{"text":"Rubrospinal","correct":true,"visible":false},{"text":"Corticospinal","correct":false,"visible":false},{"text":"Tectospinal","correct":false,"visible":false},{"text":"Corticobulbar","correct":false,"visible":false},{"text":"Vestibulospinal","correct":false,"visible":false}]},{"id":334,"text":"Which of the following is correct for the function of the blood-brain barrier (BBB)?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 453, 455.","responses":[{"text":"Provides nourishment and prevents toxic substances from entering the brain","correct":true,"visible":false},{"text":"Allows plasma proteins to enter","correct":false,"visible":false},{"text":"Synthesizes fibroblasts","correct":false,"visible":false},{"text":"Does not maintain a constant environment in the brain","correct":false,"visible":false},{"text":"Allows the big molecules to enter the brain","correct":false,"visible":false}]},{"id":337,"text":"Which of the following accurately describes the action of cimetidine on warfarin?","explanation":null,"reference":"Crader MF, Johns T, Arnold JK. Warfarin drug interactions. In: StatPearls. StatPearls Publishing; 2022. Accessed March 28, 2022. http://www.ncbi.nlm.nih.gov/books/NBK441964/","responses":[{"text":"Affects the activity of the platelets","correct":false,"visible":false},{"text":"Increases the metabolism of warfarin","correct":false,"visible":false},{"text":"Decreases the affinity of warfarin for vitamin K epoxide reductase","correct":false,"visible":false},{"text":"Decreases the metabolism of warfarin","correct":true,"visible":false},{"text":"Increases the affinity of warfarin for vitman K epoxide reductase","correct":false,"visible":false}]},{"id":338,"text":"Which of the following contains respiratory center in the brain?","explanation":null,"reference":"Whited L, Graham D. Abnormal respirations. StatPearls. Published online July 26, 2021. Accessed March 28, 2022. https://www.statpearls.com/articlelibrary/viewarticle/23959","responses":[{"text":"Pons","correct":false,"visible":false},{"text":"Thalamus","correct":false,"visible":false},{"text":"Medulla","correct":true,"visible":false},{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Hypothalamus","correct":false,"visible":false}]},{"id":342,"text":"Histamine is synthesized from which of the following?","explanation":null,"reference":"Huang H, Li Y, Liang J, Finkelman FD. Molecular regulation of histamine synthesis. Frontiers in Immunology.","responses":[{"text":"Methionine","correct":false,"visible":false},{"text":"Proline","correct":false,"visible":false},{"text":"Histidine","correct":true,"visible":false},{"text":"Serine","correct":false,"visible":false},{"text":"Valine","correct":false,"visible":false}]},{"id":344,"text":"Chronic hypertension is the most critical risk factor for developing which of the following types of brain aneurysms?","explanation":null,"reference":"Gupta K, M Das J. Charcot bouchard aneurysm. In: StatPearls. StatPearls Publishing; 2022. Accessed March 28, 2022. http://www.ncbi.nlm.nih.gov/books/NBK553028/","responses":[{"text":"Traumatic aneurysm","correct":false,"visible":false},{"text":"Charcot-Bouchard aneurysm","correct":true,"visible":false},{"text":"Sacular aneurysm","correct":false,"visible":false},{"text":"Dissecting aneurysm","correct":false,"visible":false},{"text":"Mycotic aneurysm","correct":false,"visible":false}]},{"id":347,"text":"An 8-year-old boy fractured his skull during his fall. What is the first modality to be used for the examination of the fracture of the skull?","explanation":null,"reference":"Bruce DA. Imaging after head trauma: why, when and which. Child’s Nervous System: ChNS: Official Journal of the International Society for Pediatric Neurosurgery.","responses":[{"text":"X-ray","correct":false,"visible":false},{"text":"PET scan","correct":false,"visible":false},{"text":"MRI","correct":false,"visible":false},{"text":"Myelography","correct":false,"visible":false},{"text":"CT scan","correct":true,"visible":false}]},{"id":348,"text":"Which of the following cranial nerve nuclei are present in the midbrain?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 332, 333.","responses":[{"text":"III and IV","correct":false,"visible":false},{"text":"IV only","correct":false,"visible":false},{"text":"III, IV, and V","correct":true,"visible":false},{"text":"V, VI, and IV","correct":false,"visible":false},{"text":"III only","correct":false,"visible":false}]},{"id":350,"text":"Damage to which one of the following structures of the midbrain produces auditory disturbance?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 211.","responses":[{"text":"Lateral geniculate body","correct":false,"visible":false},{"text":"Inferior colliculi","correct":true,"visible":false},{"text":"Superior colliculi","correct":false,"visible":false},{"text":"Superior brachium","correct":false,"visible":false},{"text":"Medial geniculate body","correct":false,"visible":false}]},{"id":353,"text":"What is dopamine synthesized from?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 285.","responses":[{"text":"Tyrosine","correct":true,"visible":false},{"text":"Tryptophan","correct":false,"visible":false},{"text":"Phenylalanine","correct":false,"visible":false},{"text":"Glycine","correct":false,"visible":false},{"text":"Glutamate","correct":false,"visible":false}]},{"id":354,"text":"The extrapyramidal motor system includes the pathway stemming from which of the following points of origin?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 153, 290.","responses":[{"text":"Primary motor cortex","correct":false,"visible":false},{"text":"Secondary motor cortex","correct":true,"visible":false},{"text":"Inferior colliculus","correct":false,"visible":false},{"text":"Parietal lobe","correct":false,"visible":false},{"text":"Areas 3, 1, and 2","correct":false,"visible":false}]},{"id":357,"text":"Which one of the following signs and symptom occurs in Wernicke's sensory area lesion?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 296.","responses":[{"text":"Inability to read","correct":false,"visible":false},{"text":"Inability to write","correct":false,"visible":false},{"text":"Inability to understand and read only","correct":false,"visible":false},{"text":"Inability to speech","correct":false,"visible":false},{"text":"Inability to understand, read and write","correct":true,"visible":false}]},{"id":358,"text":"What is the rate limiting enzyme in serotonin synthesis?","explanation":null,"reference":"Tryptophan hydroxylase - an overview | sciencedirect topics. Accessed March 28, 2022. https://www.sciencedirect.com/topics/neuroscience/tryptophan-hydroxylase","responses":[{"text":"Mono amine oxidase","correct":false,"visible":false},{"text":"Tryptophan hydroxylase","correct":true,"visible":false},{"text":"5-hydroxy tryptophane decarboxylase","correct":false,"visible":false},{"text":"Dopa decarboxylase","correct":false,"visible":false},{"text":"Aldehyde dehydrogenase","correct":false,"visible":false}]},{"id":361,"text":"What is the function of the vestibular nucleus present in the brainstem?","explanation":null,"reference":"Medical physiology. Accessed March 25, 2022. https://www.euroformhealthcare.biz/medical-physiology/","responses":[{"text":"Muscle spasm","correct":false,"visible":false},{"text":"REM sleep and non-REM sleep","correct":false,"visible":false},{"text":"Antigravity muscles to maintain equilibrium","correct":true,"visible":false},{"text":"Respiratory system","correct":false,"visible":false},{"text":"Cardiovascular system","correct":false,"visible":false}]},{"id":363,"text":"What is glycine in the brainstem characterized as?","explanation":null,"reference":"López-Corcuera B, Geerlings A, Aragón C. Glycine neurotransmitter transporters: an update. Molecular Membrane Biology.","responses":[{"text":"Amine derivative","correct":false,"visible":false},{"text":"Inhibitory neurotransmitter","correct":true,"visible":false},{"text":"Glycoprotein derivative","correct":false,"visible":false},{"text":"Excitatory neurotransmitter","correct":false,"visible":false},{"text":"Choline derivative","correct":false,"visible":false}]},{"id":364,"text":"Which of the following correctly describes the Golgi tendon organs?","explanation":null,"reference":"Golgi tendon organ - an overview | sciencedirect topics. Accessed March 27, 2022. https://www.sciencedirect.com/topics/neuroscience/golgi-tendon-organ","responses":[{"text":"Intrafusal fibers contractor","correct":false,"visible":false},{"text":"Neurotransmitters","correct":false,"visible":false},{"text":"Proprioceptors","correct":true,"visible":false},{"text":"Muscle spindles","correct":false,"visible":false},{"text":"Muscle relaxer","correct":false,"visible":false}]},{"id":366,"text":"Which of the following is not present in the granular cell layer of the cerebellum?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 259.","responses":[{"text":"Soma and axons of Golgi cells","correct":false,"visible":false},{"text":"Cerebellar glomeruli","correct":false,"visible":false},{"text":"Axons of purkinje cells","correct":false,"visible":false},{"text":"Soma and dendrites of granule cells","correct":false,"visible":false},{"text":"Granule cell axons","correct":true,"visible":false}]},{"id":368,"text":"What is the most likely cause of an increase in proteins in cerebrospinal (CSF)?","explanation":null,"reference":"Protein cerebrospinal fluid level - an overview | sciencedirect topics. Accessed March 28, 2022. https://www.sciencedirect.com/topics/biochemistry-genetics-and-molecular-biology/protein-cerebrospinal-fluid-level","responses":[{"text":"Hyperuricemia","correct":false,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Breach in blood brain barrier","correct":true,"visible":false}]},{"id":373,"text":"A patient presents with right-sided hemiplegia and loss of speech. Upon examination, both of his eyes deviate to the left. Damage to which artery can present with these symptoms?","explanation":null,"reference":"(1) Derakhshan I. How do the eyes move together? New understandings help explain eye deviations in patients with stroke. CMAJ : Canadian Medical Association Journal. Published January 18, 2005. Accessed March 25, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC543974/\r\n\r\n(2) Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 483.","responses":[{"text":"Anterior cerebral artery","correct":false,"visible":false},{"text":"Middle cerebral artery","correct":true,"visible":false},{"text":"Posterior communicating artery","correct":false,"visible":false},{"text":"Posterior cerebral artery","correct":false,"visible":false},{"text":"Anterior communicating artery","correct":false,"visible":false}]},{"id":375,"text":"Which one of the following is the histological feature of a peripheral nerve?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 80.","responses":[{"text":"Epineurium is a thin, regular collagenous coat","correct":false,"visible":false},{"text":"Around Schwann cells is a thin layer called the perineurium, consisting of reticular fibers","correct":false,"visible":false},{"text":"Each fascicle in invested by collagenous covering called perineurium","correct":true,"visible":false},{"text":"Epineurium does not extend deeply to fill the space between fascicles","correct":false,"visible":false},{"text":"Axons and Schwann cells are not enclosed within layers of connective tissue","correct":false,"visible":false}]},{"id":376,"text":"Histologically, the neurons of the cerebral cortex do not include which of the following cells?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 285.","responses":[{"text":"Pyramidal cells","correct":false,"visible":false},{"text":"Purkinje cells","correct":true,"visible":false},{"text":"Fusiform cells","correct":false,"visible":false},{"text":"Betz cell","correct":false,"visible":false},{"text":"Granule cell","correct":false,"visible":false}]},{"id":377,"text":"Which one of the following is the distinguishing feature of the midbrain at the superior colliculus level?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 157.","responses":[{"text":"Fourth ventricle","correct":false,"visible":false},{"text":"Cerebral aqueduct","correct":false,"visible":false},{"text":"Red nucleus","correct":true,"visible":false},{"text":"Third ventricle","correct":false,"visible":false},{"text":"Third and fourth ventricle","correct":false,"visible":false}]},{"id":379,"text":"Hyperalgesia and allodynia signify which of the following statements?","explanation":null,"reference":"Jensen TS, Finnerup NB. Allodynia and hyperalgesia in neuropathic pain: clinical manifestations and mechanisms. The Lancet. Neurology.","responses":[{"text":"Tissue repair","correct":false,"visible":false},{"text":"No release of chemicals","correct":false,"visible":false},{"text":"Increased sensitivity of pain","correct":true,"visible":false},{"text":"Release of coagulation factors","correct":false,"visible":false},{"text":"Decreased sensitivity of pain","correct":false,"visible":false}]},{"id":380,"text":"Which one of the following nerves is not present at the lateral wall of the cavernous sinus?","explanation":null,"reference":"Cavernous sinus - an overview | sciencedirect topics. Accessed March 27, 2022. https://www.sciencedirect.com/topics/neuroscience/cavernous-sinus","responses":[{"text":"Ophthalmic nerve","correct":false,"visible":false},{"text":"6th cranial nerve","correct":true,"visible":false},{"text":"3rd cranial nerve","correct":false,"visible":false},{"text":"Maxillary nerve","correct":false,"visible":false},{"text":"4th cranial nerve","correct":false,"visible":false}]},{"id":381,"text":"Which nucleus is not present on the floor of the fourth ventricle?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 226, 338, 463.","responses":[{"text":"7 cranial nucleus","correct":false,"visible":false},{"text":"9 cranial nucleus","correct":true,"visible":false},{"text":"6 cranial nucleus","correct":false,"visible":false},{"text":"10 cranial nucleus","correct":false,"visible":false},{"text":"12 cranial nucleus","correct":false,"visible":false}]},{"id":382,"text":"In bacterial meningitis, compared to normal cerebrospinal fluid, which of the following is found to be typically decreased?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 180.","responses":[{"text":"Proteins","correct":false,"visible":false},{"text":"Neutrophils","correct":false,"visible":false},{"text":"Sodium","correct":false,"visible":false},{"text":"Glucose","correct":true,"visible":false},{"text":"Chloride","correct":false,"visible":false}]},{"id":383,"text":"In lower motor neuron lesions, patient develops which of the following conditions?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 166.","responses":[{"text":"Hyperesthesia","correct":false,"visible":false},{"text":"Spasticity","correct":false,"visible":false},{"text":"Positive babinski's sign","correct":false,"visible":false},{"text":"Hyperreflexia","correct":false,"visible":false},{"text":"Muscular wasting, hypotonia","correct":true,"visible":false}]},{"id":384,"text":"The insula lies at the bottom of which of the following structures?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 512.","responses":[{"text":"Precentral gyrus","correct":false,"visible":false},{"text":"Central sulcus","correct":false,"visible":false},{"text":"Calcarine sulcus","correct":false,"visible":false},{"text":"Lateral sulcus","correct":true,"visible":false},{"text":"Parieto-occipital sulcus","correct":false,"visible":false}]},{"id":385,"text":"Which of the following key enzymes is required for the synthesis of acetylcholine?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 273.","responses":[{"text":"Acetyl cholineaminase","correct":false,"visible":false},{"text":"Choline synthetase","correct":false,"visible":false},{"text":"Choline acyltransferase","correct":false,"visible":false},{"text":"Choline acetyltransferase","correct":true,"visible":false},{"text":"Choline acetylsynthetase","correct":false,"visible":false}]},{"id":386,"text":"Lack of dopamine and degeneration of substantia nigra leads to abnormal movement and is referred to as which of the following?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 173.","responses":[{"text":"Parkinson disease","correct":true,"visible":false},{"text":"Athetosis","correct":false,"visible":false},{"text":"Huntington chorea","correct":false,"visible":false},{"text":"Wilson disease","correct":false,"visible":false},{"text":"Chorea","correct":false,"visible":false}]},{"id":387,"text":"Lesion in cerebellum causes which of the following clinical conditions?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 243, 244.","responses":[{"text":"Athermia","correct":false,"visible":false},{"text":"Aphasia","correct":false,"visible":false},{"text":"Aphagia","correct":false,"visible":false},{"text":"Difficulty in balance and gait","correct":true,"visible":false},{"text":"Mental retardation","correct":false,"visible":false}]},{"id":389,"text":"Which of the following is a  major relay centre for sensory afferents?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 252.","responses":[{"text":"Red nucleus","correct":false,"visible":false},{"text":"Thalamus","correct":true,"visible":false},{"text":"Hypothalamus","correct":false,"visible":false},{"text":"Cerebellum","correct":false,"visible":false},{"text":"Basal nucleus","correct":false,"visible":false}]},{"id":391,"text":"Which nucleus of the hypothalamus is involved in the regulation of thirst and hunger?","explanation":"The **lateral nucleus** of the hypothalamus is involved in the regulation of both thirst and hunger.\r\n\r\n1. **Thirst Regulation:** The lateral hypothalamic area contains neurons that are responsible for triggering thirst sensations. When the body's water levels are low or when there is an increase in the concentration of solutes in the blood, these neurons are activated, leading to the sensation of thirst. Thirst is an essential mechanism that helps maintain proper water balance in the body.\r\n\r\n2. **Hunger Regulation:** The lateral hypothalamic area also plays a significant role in the regulation of hunger. Neurons in this region are involved in stimulating appetite and food intake. When these neurons are activated, it leads to feelings of hunger and an increased desire to eat.","reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 390.","responses":[{"text":"Lateral nucleus","correct":true,"visible":false},{"text":"Ventromedial nucleus","correct":false,"visible":false},{"text":"Suprachiasmatic nucleus","correct":false,"visible":false},{"text":"Paraventricular nucleus","correct":false,"visible":false},{"text":"Supraoptic nucleus","correct":false,"visible":false}]},{"id":400,"text":"Which of the following does not form the roof of the inferior horn of the lateral ventricle?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 440.","responses":[{"text":"Stria terminalis","correct":false,"visible":false},{"text":"Tapetum of corpus callosum","correct":false,"visible":false},{"text":"Amygdala","correct":false,"visible":false},{"text":"Pes hippocampus","correct":true,"visible":false},{"text":"Tail of caudate nucleus","correct":false,"visible":false}]},{"id":404,"text":"A 60-year-old elderly male comes to the emergency department while becoming gradually unconscious. Upon conducting magnetic resonance imaging (MRI), there is no clear finding but it is reported by his family that he is fond of eating beef. Creutzfeldt-Jacob disease is suspected. What are the histopathological findings in Creutzfeldt-Jakob disease?","explanation":null,"reference":"v Eitzen U, Egensperger R, Kösel S, et al. Microglia and the development of spongiform change in Creutzfeldt-Jakob disease. Journal of Neuropathology and Experimental Neurology.","responses":[{"text":"Demyelination","correct":false,"visible":false},{"text":"Hemorrhagic infarcts","correct":false,"visible":false},{"text":"Granulomas","correct":false,"visible":false},{"text":"Intracytoplasmic vacuoles","correct":true,"visible":false},{"text":"Necrotizing inflammation","correct":false,"visible":false}]},{"id":407,"text":"Which one of the following statements is not true about the posterior horn of the lateral ventricle?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 446.","responses":[{"text":"Superior swelling of medial wall is caused by splenial fibers of corpus callosum","correct":false,"visible":false},{"text":"Medial to tapetum optic radiations are present","correct":true,"visible":false},{"text":"Inferior swelling is produced by calcarine sulcus","correct":false,"visible":false},{"text":"Medial wall has 2 elevations","correct":false,"visible":false},{"text":"Roof and lateral wall formed by tapetum of corpus callosum","correct":false,"visible":false}]},{"id":413,"text":"Which of the following is responsible for dynamic and static control of muscle spindles?","explanation":null,"reference":"Wilkinson KA. Methodological advances for studying gamma motor neurons. Current Opinion in Physiology. Published February 1, 2021. Accessed March 27, 2022. https://www.sciencedirect.com/science/article/pii/S2468867320301309","responses":[{"text":"Withdrawal reflex","correct":false,"visible":false},{"text":"Gamma motor neurons","correct":true,"visible":false},{"text":"Intrafusal nuclear chain","correct":false,"visible":false},{"text":"Beta motor neuron","correct":false,"visible":false},{"text":"Alpha motor neurons","correct":false,"visible":false}]},{"id":416,"text":"A 40-year-old man had an accident. He was initially fine but then started developing behavioral changes after few days. On examination, he had a contusion in the frontal lobe where he hit his head in the airbag. This happened due to?","explanation":null,"reference":"Payne WN, De Jesus O, Payne AN. Contrecoup brain injury. In: StatPearls. StatPearls Publishing; 2022. Accessed March 27, 2022. http://www.ncbi.nlm.nih.gov/books/NBK536965/","responses":[{"text":"Excessive bleeding","correct":false,"visible":false},{"text":"Hematoma","correct":false,"visible":false},{"text":"Coup","correct":true,"visible":false},{"text":"Contrecoup","correct":false,"visible":false},{"text":"Fracture","correct":false,"visible":false}]},{"id":418,"text":"Which of the following is not a derivative of neuroectoderm?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 318.","responses":[{"text":"Macroglia","correct":false,"visible":false},{"text":"Microglia","correct":true,"visible":false},{"text":"Ependyma","correct":false,"visible":false},{"text":"Oligodendrocytes","correct":false,"visible":false},{"text":"Astrocytes","correct":false,"visible":false}]},{"id":421,"text":"Damping of the motor movements is done by which of the following?","explanation":null,"reference":"Manto M. Mechanisms of human cerebellar dysmetria: experimental evidence and current conceptual bases. Journal of NeuroEngineering and Rehabilitation. Published April 13, 2009. Accessed March 26, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2679756/","responses":[{"text":"Reticular system","correct":false,"visible":false},{"text":"Limbic system","correct":false,"visible":false},{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Midbrain","correct":false,"visible":false},{"text":"Cerebellum","correct":true,"visible":false}]},{"id":424,"text":"Which of the following is not a characteristic of midbrain when a transverse section is taken at the level of superior colliculus?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 215.","responses":[{"text":"Occulomotor nerve fibers","correct":false,"visible":false},{"text":"Trochlear nerve fibers","correct":true,"visible":false},{"text":"Red nucleus","correct":false,"visible":false},{"text":"Mesencephalic nucleus","correct":false,"visible":false},{"text":"Cerebral aqueduct","correct":false,"visible":false}]},{"id":428,"text":"Which of the following is the first choice of modality for diagnosing and examining suspected spinal cord lesions in patients who have suffered trauma?","explanation":null,"reference":"van Middendorp JJ, Goss B, Urquhart S, Atresh S, Williams RP, Schuetz M. Diagnosis and prognosis of traumatic spinal cord injury. Global Spine Journal. Published December 2011. Accessed March 26, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3864437/","responses":[{"text":"X-ray","correct":false,"visible":false},{"text":"Magnetic resonance imaging","correct":true,"visible":false},{"text":"Computed tomography scan","correct":false,"visible":false},{"text":"Electroencephalography","correct":false,"visible":false},{"text":"Positron emission tomography scan","correct":false,"visible":false}]},{"id":433,"text":"Facial colliculus is formed due to the looping around which of the following nuclei?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 206.","responses":[{"text":"Abducens nucleus","correct":true,"visible":false},{"text":"Facial motor nucleus","correct":false,"visible":false},{"text":"Lacrimal nucleus","correct":false,"visible":false},{"text":"Nucleus ambiguous","correct":false,"visible":false},{"text":"Salivatory nucleus","correct":false,"visible":false}]},{"id":438,"text":"Which nucleus supplies soft palate and pharynx and has fibers from the glossopharyngeal and vagus nerve?","explanation":null,"reference":"Petko B, Tadi P. Neuroanatomy, nucleus ambiguus. In: StatPearls. StatPearls Publishing; 2022. Accessed March 26, 2022. http://www.ncbi.nlm.nih.gov/books/NBK547744/","responses":[{"text":"Facial nucleus","correct":false,"visible":false},{"text":"Trochlear nucleus","correct":false,"visible":false},{"text":"Abducens nucleus","correct":false,"visible":false},{"text":"Trigeminal nucleus","correct":false,"visible":false},{"text":"Nucleus ambiguous","correct":true,"visible":false}]},{"id":441,"text":"Fracture of which one of the following can damage facial nerve?","explanation":null,"reference":"Jones J. Internal acoustic canal | radiology reference article | radiopaedia. Org. Radiopaedia. doi:10.53347/rID-4514","responses":[{"text":"Posterior cranial fossa","correct":true,"visible":false},{"text":"Middle cranial fossa","correct":false,"visible":false},{"text":"Anterior cranial fossa","correct":false,"visible":false},{"text":"Jugular Foramen","correct":false,"visible":false},{"text":"Ethmoid bone","correct":false,"visible":false}]},{"id":445,"text":"Before entering the tricarboxylic acid cycle, glucose is metabolized into pyruvate which enters the mitochondria of neurons and glial cells in the form of?","explanation":null,"reference":"Molnar C, Gair J. 4. 3 citric acid cycle and oxidative phosphorylation. Published online May 14, 2015. Accessed March 26, 2022. https://opentextbc.ca/biology/chapter/4-3-citric-acid-cycle-and-oxidative-phosphorylation/","responses":[{"text":"Citrate","correct":false,"visible":false},{"text":"Lactate","correct":false,"visible":false},{"text":"Glutamic acid","correct":false,"visible":false},{"text":"Oxaloacetate","correct":false,"visible":false},{"text":"Acetyl CoA","correct":true,"visible":false}]},{"id":447,"text":"How many layers are present in the cerebrum and cerebellum respectively?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 231, 287.","responses":[{"text":"3 layers, 6 layers","correct":false,"visible":false},{"text":"4 layers, 6 layers","correct":false,"visible":false},{"text":"3 layers, 3 layers","correct":false,"visible":false},{"text":"3 layers, 1 layer","correct":false,"visible":false},{"text":"6 layers, 3 layers","correct":true,"visible":false}]},{"id":448,"text":"Which of the following is the main function of blood-brain barrier?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 453.","responses":[{"text":"Supplies nutrients while preventing hazardous chemicals from reaching the brain","correct":true,"visible":false},{"text":"Provides another layer of cerebrospinal fluid","correct":false,"visible":false},{"text":"Transmits electrical signals between neurons","correct":false,"visible":false},{"text":"Secretes neurotransmitters","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":449,"text":"A patient is suffering from wakefulness and narcolepsy. Which one of the following is affected?","explanation":null,"reference":"Hall JE. Guyton and Hall Textbook of Medical Physiology. 13th ed. Elsevier; 2016: 765.","responses":[{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Spinothalamic tract","correct":false,"visible":false},{"text":"Medial lemniscus","correct":false,"visible":false},{"text":"Cerebelllum","correct":false,"visible":false},{"text":"Reticular formation","correct":true,"visible":false}]},{"id":453,"text":"Which one of the following innervates intrafusal muscle fibers?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 686.","responses":[{"text":"Alpha fibers","correct":false,"visible":false},{"text":"Unmyelinated fibers","correct":false,"visible":false},{"text":"B fibers","correct":false,"visible":false},{"text":"Both alpha and gamma fibers","correct":false,"visible":false},{"text":"Gamma fibers","correct":true,"visible":false}]},{"id":454,"text":"Which one of the following structures is not part of the sub limbic cortex?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 250, 305.","responses":[{"text":"Thalamus","correct":false,"visible":false},{"text":"Septal nuclei","correct":false,"visible":false},{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Epithalamus","correct":true,"visible":false},{"text":"Amygdala","correct":false,"visible":false}]},{"id":455,"text":"Which one of the fibers are used by sensory receptors to carry impulse from the periphery to the central nervous system?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 12.","responses":[{"text":"Preganglionic","correct":false,"visible":false},{"text":"Postganglionic","correct":false,"visible":false},{"text":"Free nerve endings","correct":false,"visible":false},{"text":"Efferent fibers","correct":false,"visible":false},{"text":"Afferent fibers","correct":true,"visible":false}]},{"id":456,"text":"Pulsatile pain is transmitted through which of the following pathways?","explanation":null,"reference":"Al-Chalabi M, Reddy V, Gupta S. Neuroanatomy, spinothalamic tract. In: StatPearls. StatPearls Publishing; 2022. Accessed March 26, 2022. http://www.ncbi.nlm.nih.gov/books/NBK507824/","responses":[{"text":"Fasciculus gracilis","correct":false,"visible":false},{"text":"Lateral spinothalamic tract","correct":true,"visible":false},{"text":"Fasciculus cuneatus","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Ventral spinothalamic tract","correct":false,"visible":false}]},{"id":457,"text":"Which one of the following is the function of ascending reticular system?","explanation":null,"reference":"Edlow BL, Takahashi E, Wu O, et al. Neuroanatomic connectivity of the human ascending arousal system critical to consciousness and its disorders. Journal of Neuropathology and Experimental Neurology. Published June 2012. Accessed March 26, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3387430/","responses":[{"text":"Gastrointestinal motility","correct":false,"visible":false},{"text":"Alertness, wakefulness","correct":true,"visible":false},{"text":"Endocrine","correct":false,"visible":false},{"text":"Respiratory","correct":false,"visible":false},{"text":"Vasomotor","correct":false,"visible":false}]},{"id":466,"text":"Which one of the following statements is incorrect about the central sulcus?","explanation":null,"reference":"Bui T, M Das J. Neuroanatomy, cerebral hemisphere. In: StatPearls. StatPearls Publishing; 2022. Accessed March 26, 2022. http://www.ncbi.nlm.nih.gov/books/NBK549789/","responses":[{"text":"Separates frontal lobe from temporal lobe","correct":true,"visible":false},{"text":"Present between two parallel gyri","correct":false,"visible":false},{"text":"Dents the super medial border of brain","correct":false,"visible":false},{"text":"Motor area is in front of the sulcus","correct":false,"visible":false},{"text":"Sensory area is behind the sulcus","correct":false,"visible":false}]},{"id":467,"text":"A boy was pushed down the hill during the fight with his friends. As a result, he acquired a head injury. On examination, a hematoma is seen between the skull base and dura mater. Which of the following arteries is involved?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 439.","responses":[{"text":"Anterior meningeal artery","correct":false,"visible":false},{"text":"Internal carotid artery","correct":false,"visible":false},{"text":"Posterior cerebral artery","correct":false,"visible":false},{"text":"Vertebral artery","correct":false,"visible":false},{"text":"Middle meningeal artery","correct":true,"visible":false}]},{"id":474,"text":"Which one of the following is best for the diagnosis of seizures?","explanation":null,"reference":"Blume WT. Diagnosis and management of epilepsy. CMAJ. 2003;168(4):441-448. Accessed March 29, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC143552/","responses":[{"text":"Electroencephalogram (EEG)","correct":true,"visible":false},{"text":"Myelography","correct":false,"visible":false},{"text":"Electroencephalogram (EEG) and Electromyography (EMG)","correct":false,"visible":false},{"text":"Nerve conduction","correct":false,"visible":false},{"text":"Electromyography (EMG)","correct":false,"visible":false}]},{"id":475,"text":"Which one of the following conditions is a neurosurgical emergency?","explanation":null,"reference":"Khairat A, Waseem M. Epidural hematoma. In: StatPearls. StatPearls Publishing; 2022. Accessed March 26, 2022. http://www.ncbi.nlm.nih.gov/books/NBK518982/","responses":[{"text":"Subarachnoid hemorrhage","correct":false,"visible":false},{"text":"Subdural hematoma","correct":false,"visible":false},{"text":"Hydrocephalus","correct":false,"visible":false},{"text":"Epidural hematoma","correct":true,"visible":false},{"text":"Intraparenchymal hemorrhage","correct":false,"visible":false}]},{"id":480,"text":"Which one of the following bone structures is related to pons?","explanation":null,"reference":"Clivus - an overview | sciencedirect topics. Accessed March 26, 2022. https://www.sciencedirect.com/topics/neuroscience/clivus","responses":[{"text":"Anterior clinoid process","correct":false,"visible":false},{"text":"Sella turcica","correct":false,"visible":false},{"text":"Meckel's cave","correct":false,"visible":false},{"text":"Clivus","correct":true,"visible":false},{"text":"Posterior clinoid process","correct":false,"visible":false}]},{"id":486,"text":"Non-REM sleep is most commonly associated with which of the following?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 512.","responses":[{"text":"Tranquilizers","correct":false,"visible":false},{"text":"Bed wetting","correct":true,"visible":false},{"text":"Nightmares","correct":false,"visible":false},{"text":"Increased systolic blood pressure","correct":false,"visible":false},{"text":"Frequent dreaming","correct":false,"visible":false}]},{"id":487,"text":"Central canal of spinal cord is continuous with:","explanation":null,"reference":"Saker E, Henry BM, Tomaszewski KA, et al. The human central canal of the spinal cord: a comprehensive review of its anatomy, embryology, molecular development, variants, and pathology. Cureus. Accessed March 26, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5234862/","responses":[{"text":"Cerebral aqueduct","correct":false,"visible":false},{"text":"Subarachnoid space","correct":false,"visible":false},{"text":"4th ventricle","correct":true,"visible":false},{"text":"Lateral ventricle","correct":false,"visible":false},{"text":"3rd ventricle","correct":false,"visible":false}]},{"id":490,"text":"What is the enlargement of the medulla formed by the cortical motor tract?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 197.","responses":[{"text":"Trapezoid body","correct":false,"visible":false},{"text":"Olives","correct":false,"visible":false},{"text":"Pyramids","correct":true,"visible":false},{"text":"Inferior olivary nucleus","correct":false,"visible":false},{"text":"Nucleus cuneatus","correct":false,"visible":false}]},{"id":491,"text":"Using morphine to treat pain may cause following adverse effect:","explanation":null,"reference":"Skarke C, Jarrar M, Erb K, Schmidt H, Geisslinger G, Lötsch J. Respiratory and miotic effects of morphine in healthy volunteers when P-glycoprotein is blocked by quinidine. Clinical Pharmacology and Therapeutics.","responses":[{"text":"Addiction","correct":false,"visible":false},{"text":"Miosis","correct":true,"visible":false},{"text":"Increase blood pressure","correct":false,"visible":false},{"text":"Mydriasis","correct":false,"visible":false},{"text":"Stimulation of respiratory centres","correct":false,"visible":false}]},{"id":492,"text":"Axons of the optic nerve are formed by central processes of which of the following?","explanation":null,"reference":"Purves D, Augustine GJ, Fitzpatrick D, et al. The retina. Neuroscience 2nd edition. Published online 2001. Accessed March 26, 2022. https://www.ncbi.nlm.nih.gov/books/NBK10885/","responses":[{"text":"Ganglion cells","correct":true,"visible":false},{"text":"Pretectal nucleus","correct":false,"visible":false},{"text":"Rods and cons","correct":false,"visible":false},{"text":"Lateral geniculate body","correct":false,"visible":false},{"text":"Bipolar cells","correct":false,"visible":false}]},{"id":493,"text":"Odd statement regarding heparin:","explanation":null,"reference":"Heparin: side effects, dosage, uses, and more. Healthline. Published December 7, 2017. Accessed March 26, 2022. https://www.healthline.com/health/drugs/heparin-injectable-solution","responses":[{"text":"Major side effect is bleeding","correct":false,"visible":false},{"text":"Does not cause bruising","correct":true,"visible":false},{"text":"Activity measured by PTT","correct":false,"visible":false},{"text":"Activity measured by aPTT","correct":false,"visible":false},{"text":"Depends on antithrombin III levels","correct":false,"visible":false}]},{"id":495,"text":"Which nerve passes through foramen rotundum?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 522.","responses":[{"text":"Lesser petrosal nerve","correct":false,"visible":false},{"text":"Ophthalmic nerve","correct":false,"visible":false},{"text":"Maxillary nerve","correct":true,"visible":false},{"text":"Abducens nerve","correct":false,"visible":false},{"text":"Mandibular nerve","correct":false,"visible":false}]},{"id":497,"text":"Rhombic alar lips of metencephalon form which of the following structures?","explanation":null,"reference":"Sadler TW, Langman J. Langman’s Medical Embryology. 12th ed. Lippincott Williams \u0026 Wilkins; 2011: 300.","responses":[{"text":"Cerebrum","correct":false,"visible":false},{"text":"Midbrain","correct":false,"visible":false},{"text":"Pons","correct":false,"visible":false},{"text":"Medulla","correct":false,"visible":false},{"text":"Cerebellum","correct":true,"visible":false}]},{"id":499,"text":"A patient has weakness and difficulty in moving the contralateral lower limb. Which of the following arteries is responsible for this?","explanation":null,"reference":"Xu Y, Liu L. Ipsilateral hemiparesis and contralateral lower limb paresis caused by anterior cerebral artery territory infarct. Neurosciences. Published July 2016. Accessed March 26, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5107294/","responses":[{"text":"Anterior cerebral","correct":true,"visible":false},{"text":"Middle cerebral","correct":false,"visible":false},{"text":"Middle meningeal","correct":false,"visible":false},{"text":"Vertebral","correct":false,"visible":false},{"text":"Posterior cerebral","correct":false,"visible":false}]},{"id":500,"text":"Which of the following is responsible for fine hand movements?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 153.","responses":[{"text":"Cerebrum","correct":false,"visible":false},{"text":"Cerebellum","correct":false,"visible":false},{"text":"Premotor cortex","correct":false,"visible":false},{"text":"Primary motor cortex","correct":true,"visible":false},{"text":"Sensory association centre","correct":false,"visible":false}]}
]

